#!/usr/bin/env python3

import json
import os
import pty
import re
import select
import signal
import subprocess
import sys
import tempfile
import time
from pathlib import Path
from typing import Optional


ROOT = Path(__file__).resolve().parents[1]
SMOKE_PID_FILE = ROOT / ".mossensrc" / "smoke-pids.json"
BACKEND_ENV_FILE = ROOT / ".mossensrc" / "custom-backend.env"
CLI = str(ROOT / "run-mossen.sh")
RUN_BUN = str(ROOT / "run-bun-featured.sh")
MAIN_TSX = ROOT / "main.tsx"
IMPORT_RE = re.compile(
    r"""(?:import\s+(?:type\s+)?(?:[^'"]+?\s+from\s+)?|export\s+[^'"]+?\s+from\s+|require\()['"]([^'"]+)['"]"""
)
ANSI_RE = re.compile(r"\x1b(?:[@-Z\\-_]|\[[0-?]*[ -/]*[@-~]|\].*?(?:\x07|\x1b\\))")
EXPORT_ENV_RE = re.compile(r"""^\s*export\s+([A-Za-z_][A-Za-z0-9_]*)=(['"])(.*)\2\s*$""")
SHELL_DEFAULT_EXPANSION_RE = re.compile(
    r"""\$\{([A-Za-z_][A-Za-z0-9_]*)(?:(:?)-([^}]*))?\}"""
)
API_CONNECT_ERROR_TEXT = (
    "API Error: Unable to connect. Is the computer able to access the url?"
)


def external_text(*codes: int) -> str:
    return "".join(chr(code) for code in codes)


# External provider boundary: raw provider model IDs still use provider-shaped
# stems at adapter/API edges. Keep those fixtures constructed here instead of
# scattering legacy brand literals through smoke expectations.
EXTERNAL_PROVIDER_MODEL_PREFIX = external_text(99, 108, 97, 117, 100, 101)
LEGACY_PRODUCT_NAME = external_text(67, 108, 97, 117, 100, 101)
LEGACY_PRODUCT_LOWER = LEGACY_PRODUCT_NAME.lower()
LEGACY_VENDOR_NAME = external_text(65, 110, 116, 104, 114, 111, 112, 105, 99)
LEGACY_VENDOR_LOWER = LEGACY_VENDOR_NAME.lower()
LEGACY_BRAND_FORBIDDEN_GUIDANCE = (
    "/login",
    "OAuth",
    LEGACY_PRODUCT_NAME,
    LEGACY_PRODUCT_LOWER,
)
MOSSEN_OPUS_3 = "mossen-3-opus-20240229"
MOSSEN_OPUS_4_5_DATED = "mossen-opus-4-5-20251101"
MOSSEN_OPUS_4_6 = "mossen-opus-4-6"
MOSSEN_HAIKU_3 = "mossen-3-haiku-20240307"
MOSSEN_HAIKU_4_5 = "mossen-haiku-4-5"
MOSSEN_SONNET_3_7_DATED = "mossen-3-7-sonnet-20250219"
MOSSEN_SONNET_4 = "mossen-sonnet-4"
MOSSEN_SONNET_4_6 = "mossen-sonnet-4-6"


def external_provider_model_id(model_tail: str) -> str:
    return f"{EXTERNAL_PROVIDER_MODEL_PREFIX}-{model_tail}"


def legacy_phrase(template: str) -> str:
    return (
        template.replace("<<LEGACY_PRODUCT_TITLE>>", LEGACY_PRODUCT_NAME)
        .replace("<<LEGACY_PRODUCT_LOWER>>", LEGACY_PRODUCT_LOWER)
        .replace("<<LEGACY_VENDOR_TITLE>>", LEGACY_VENDOR_NAME)
        .replace("<<LEGACY_VENDOR_LOWER>>", LEGACY_VENDOR_LOWER)
    )


def legacy_env_name(suffix: str) -> str:
    return f"{LEGACY_PRODUCT_NAME.upper()}_{suffix}"


def load_smoke_pids() -> list[int]:
    if not SMOKE_PID_FILE.exists():
        return []
    try:
        data = json.loads(SMOKE_PID_FILE.read_text())
    except Exception:
        return []
    if not isinstance(data, list):
        return []
    return [pid for pid in data if isinstance(pid, int)]


def save_smoke_pids(pids: list[int]) -> None:
    SMOKE_PID_FILE.parent.mkdir(parents=True, exist_ok=True)
    SMOKE_PID_FILE.write_text(json.dumps(sorted(set(pids))))


def register_smoke_pid(pid: int) -> None:
    pids = load_smoke_pids()
    pids.append(pid)
    save_smoke_pids(pids)


def unregister_smoke_pid(pid: int) -> None:
    pids = [value for value in load_smoke_pids() if value != pid]
    if pids:
        save_smoke_pids(pids)
    elif SMOKE_PID_FILE.exists():
        SMOKE_PID_FILE.unlink()


def reap_stale_smoke_processes() -> None:
    stale = load_smoke_pids()
    if not stale:
        return
    for pid in stale:
        try:
            os.killpg(pid, signal.SIGTERM)
        except ProcessLookupError:
            continue
        except PermissionError:
            try:
                os.kill(pid, signal.SIGTERM)
            except OSError:
                pass
    time.sleep(0.5)
    for pid in stale:
        try:
            os.killpg(pid, signal.SIGKILL)
        except ProcessLookupError:
            continue
        except PermissionError:
            try:
                os.kill(pid, signal.SIGKILL)
            except OSError:
                pass
    if SMOKE_PID_FILE.exists():
        SMOKE_PID_FILE.unlink()


def run_cmd(args: list[str], timeout: int = 30) -> str:
    proc = subprocess.run(
        args,
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=timeout,
        check=True,
    )
    return proc.stdout.strip()


def run_cmd_full(args: list[str], timeout: int = 30) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        args,
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=timeout,
    )


def run_cmd_full_retry(
    args: list[str],
    timeout: int = 30,
    retries: int = 2,
    retry_delay: float = 1.0,
) -> subprocess.CompletedProcess[str]:
    last_error: Optional[subprocess.TimeoutExpired] = None
    for attempt in range(retries):
        try:
            return run_cmd_full(args, timeout=timeout)
        except subprocess.TimeoutExpired as exc:
            last_error = exc
            if attempt + 1 < retries:
                time.sleep(retry_delay)
    assert last_error is not None
    raise last_error


def normalize_output(data: str) -> str:
    data = ANSI_RE.sub("", data)
    data = data.replace("\r", "")
    data = data.replace("\xa0", " ")
    return data


def expand_shell_style_defaults(value: str, env: dict[str, str]) -> str:
    def replace(match: re.Match[str]) -> str:
        key, colon, default = match.groups()
        current = os.environ.get(key)
        if current is None:
            current = env.get(key)
        if current is not None and (not colon or current != ""):
            return current
        if default is None:
            return current or ""
        return expand_shell_style_defaults(default, env)

    previous = None
    expanded = value
    while expanded != previous:
        previous = expanded
        expanded = SHELL_DEFAULT_EXPANSION_RE.sub(replace, expanded)
    return expanded


def parse_exported_env_file(path: Path) -> dict[str, str]:
    if not path.exists():
        return {}

    env: dict[str, str] = {}
    for raw_line in path.read_text(errors="ignore").splitlines():
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        match = EXPORT_ENV_RE.match(line)
        if not match:
            continue
        key, _, value = match.groups()
        env[key] = expand_shell_style_defaults(value, env)
    return env


def get_active_custom_backend_env() -> dict[str, str]:
    env = parse_exported_env_file(BACKEND_ENV_FILE)
    merged: dict[str, str] = {}
    for key in (
        "MOSSEN_CODE_USE_CUSTOM_BACKEND",
        "MOSSEN_CODE_CUSTOM_BASE_URL",
        "MOSSEN_CODE_CUSTOM_API_KEY",
        "MOSSEN_CODE_CUSTOM_MODEL",
        "MOSSEN_CODE_CUSTOM_BACKEND_PROTOCOL",
        "MOSSEN_CODE_CUSTOM_NAME",
    ):
        value = os.environ.get(key)
        if value is not None:
            merged[key] = value
        elif key in env:
            merged[key] = env[key]
    return merged


def iter_nested_strings(value: object) -> list[str]:
    results: list[str] = []
    if isinstance(value, str):
        results.append(value)
    elif isinstance(value, dict):
        for nested in value.values():
            results.extend(iter_nested_strings(nested))
    elif isinstance(value, list):
        for nested in value:
            results.extend(iter_nested_strings(nested))
    return results


def respond_to_terminal_queries(fd: int, chunk: str) -> None:
    """Answer terminal capability probes emitted by the TUI inside a test PTY."""
    responses: list[str] = []
    if "\x1b[>0q" in chunk:
        responses.append("\x1bP>|mossen-smoke\x1b\\")
    responses.extend("\x1b[?1;2c" for _ in range(chunk.count("\x1b[c")))
    responses.extend("\x1b[>0;0;0c" for _ in range(chunk.count("\x1b[>c")))
    if not responses:
        return
    try:
        os.write(fd, "".join(responses).encode("utf-8"))
    except OSError:
        pass


def wait_for_text(fd: int, patterns: list[str], timeout: float) -> tuple[str, str]:
    deadline = time.time() + timeout
    data = ""
    while time.time() < deadline:
        remaining = max(0.1, deadline - time.time())
        readable, _, _ = select.select([fd], [], [], remaining)
        if not readable:
            continue
        try:
            chunk = os.read(fd, 4096).decode("utf-8", errors="ignore")
        except OSError:
            break
        if not chunk:
            break
        respond_to_terminal_queries(fd, chunk)
        data += chunk
        normalized = normalize_output(data)
        for pattern in patterns:
            if pattern in normalized:
                return pattern, normalized
    raise TimeoutError(f"Timed out waiting for one of: {patterns!r}\n--- output ---\n{data}")


def spawn_cli(args: Optional[list[str]] = None) -> tuple[subprocess.Popen[bytes], int]:
    master_fd, slave_fd = pty.openpty()
    argv = [CLI, *(args or [])]
    proc = subprocess.Popen(
        argv,
        cwd=ROOT,
        stdin=slave_fd,
        stdout=slave_fd,
        stderr=slave_fd,
        close_fds=True,
        start_new_session=True,
    )
    os.close(slave_fd)
    register_smoke_pid(proc.pid)
    return proc, master_fd


def write_line(fd: int, text: str) -> None:
    os.write(fd, text.encode("utf-8"))


def terminate_process_tree(proc: subprocess.Popen[bytes], timeout: float = 3) -> None:
    if proc.poll() is not None:
        unregister_smoke_pid(proc.pid)
        return
    try:
        os.killpg(proc.pid, signal.SIGTERM)
    except ProcessLookupError:
        unregister_smoke_pid(proc.pid)
        return
    except PermissionError:
        try:
            proc.terminate()
        except ProcessLookupError:
            unregister_smoke_pid(proc.pid)
            return
    deadline = time.time() + timeout
    while time.time() < deadline:
        if proc.poll() is not None:
            unregister_smoke_pid(proc.pid)
            return
        time.sleep(0.1)
    try:
        os.killpg(proc.pid, signal.SIGKILL)
    except ProcessLookupError:
        unregister_smoke_pid(proc.pid)
        return
    except PermissionError:
        try:
            proc.kill()
        except ProcessLookupError:
            unregister_smoke_pid(proc.pid)
            return
    unregister_smoke_pid(proc.pid)


def exit_cli(proc: subprocess.Popen[bytes], fd: int) -> None:
    write_line(fd, "/exit\n")
    deadline = time.time() + 15
    while time.time() < deadline:
        code = proc.poll()
        if code is not None:
            if code != 0:
                raise RuntimeError(f"TUI exited with code {code}")
            return
        time.sleep(0.2)
    terminate_process_tree(proc)


def list_static_program_commands() -> list[str]:
    text = MAIN_TSX.read_text(errors="ignore")
    return [match.split()[0] for match in re.findall(r"program\.command\('([^']+)'\)", text)]


def list_exposed_program_commands() -> list[str]:
    output = run_cmd([CLI, "--help"])
    match = re.search(r"Commands:\n([\s\S]+)$", output)
    if not match:
        return []
    commands: list[str] = []
    for raw_line in match.group(1).splitlines():
        line = raw_line.rstrip()
        if not line.strip():
            continue
        token = line.strip().split()[0]
        if token == "help":
            continue
        commands.append(token)
    return commands


def expect_contains(output: str, needle: str, label: str) -> None:
    if needle not in output:
        raise RuntimeError(
            f"{label} missing expected text {needle!r}\n--- output ---\n{output[:1200]}"
        )


def is_mossen_backend_connectivity_gate(output: str) -> bool:
    normalized = normalize_output(output)
    compact = re.sub(r"\s+", "", normalized)
    return (
        "Unabletoconnecttobackendservices" in compact
        and (
            "backendanditsauthendpoints" in compact
            or "Failedtoconnecttoapi.mossen.invalid" in compact
        )
        and all(token not in normalized for token in LEGACY_BRAND_FORBIDDEN_GUIDANCE)
    )


def run_print_smoke() -> dict[str, object]:
    proc = run_cmd_full([CLI, "-p", "Reply with exactly: smoke ok"], timeout=60)
    stdout = normalize_output(proc.stdout or "")
    stderr = normalize_output(proc.stderr or "")
    output = (stdout + "\n" + stderr).strip()
    hard_cut_backend_error = (
        "API Error: Custom backend mode requires MOSSEN_CODE_CUSTOM_BASE_URL to be set."
    )
    forbidden_guidance = LEGACY_BRAND_FORBIDDEN_GUIDANCE

    if proc.returncode == 0 and "smoke ok" in stdout:
        return {
            "status": "ok",
            "classification": "runtime-print-smoke-provider-request-completed",
        }

    if (
        proc.returncode != 0
        and hard_cut_backend_error in output
        and all(token not in output for token in forbidden_guidance)
    ):
        return {
            "status": "ok",
            "classification": "runtime-print-smoke-hard-cut-custom-backend-config-required",
            "returncode": proc.returncode,
        }

    raise RuntimeError(
        json.dumps(
            {
                "print_smoke_failed": {
                    "returncode": proc.returncode,
                    "stdout": stdout[:1200],
                    "stderr": stderr[:1200],
                },
                "expected": {
                    "success": "stdout contains smoke ok",
                    "hardCut": hard_cut_backend_error,
                    "forbiddenGuidance": forbidden_guidance,
                },
            },
            ensure_ascii=False,
            indent=2,
        )
    )


def count_bullet_entries(output: str) -> int:
    return len(re.findall(r"^\s*❯\s+", normalize_output(output), re.MULTILINE))


def get_project_session_dir(platform_report: dict[str, object]) -> Path:
    runtime = platform_report.get("runtime") or {}
    sessions = runtime.get("sessions") or {}
    transcript = sessions.get("currentTranscriptPath")
    if not isinstance(transcript, str) or not transcript:
        raise RuntimeError("platform_check missing runtime.sessions.currentTranscriptPath")
    return Path(transcript).parent


def list_session_files(session_dir: Path) -> list[Path]:
    return sorted(session_dir.glob("*.jsonl"), key=lambda p: p.stat().st_mtime, reverse=True)


def find_new_session_file(before: set[str], after: list[Path]) -> Path:
    for path in after:
        if str(path) not in before:
            return path
    raise RuntimeError("did not find newly created session transcript")


def run_help_matrix() -> dict[str, object]:
    results: dict[str, object] = {}
    failures: list[dict[str, str]] = []
    for command in list_exposed_program_commands():
        invoke = command.split("|")[0]
        proc = subprocess.run(
            [CLI, invoke, "--help"],
            cwd=ROOT,
            text=True,
            capture_output=True,
            timeout=30,
        )
        combined = (proc.stdout + proc.stderr).strip()
        ok = proc.returncode == 0 and "Usage:" in combined and invoke in combined
        results[command] = "ok" if ok else f"bad:{proc.returncode}"
        if not ok:
            failures.append(
                {
                    "command": command,
                    "returncode": str(proc.returncode),
                    "output": combined[:600],
                }
            )
    if failures:
        raise RuntimeError(json.dumps({"help_failures": failures}, ensure_ascii=False, indent=2))
    return results


def run_platform_command_surface_audit() -> dict[str, object]:
    platform_check = json.loads(run_cmd([RUN_BUN, "scripts/platform_check.ts"], timeout=60))
    runtime = platform_check.get("runtime") or {}
    direct_connect = runtime.get("directConnect") or {}
    ssh_remote = runtime.get("sshRemote") or {}
    remote = runtime.get("remote") or {}
    assistant = runtime.get("assistant") or {}
    manifest = runtime.get("manifest") or []
    manifest_status = {
        entry.get("id"): entry.get("status")
        for entry in manifest
        if isinstance(entry, dict)
    }
    exposed = {entry.split("|")[0] for entry in list_exposed_program_commands()}

    classifications = {
        "direct_connect_server_surface": {
            "classification": "runtime-direct-connect-server-help-alignment",
            "runtime_exposed": bool(direct_connect.get("serverCommandExposed")),
            "help_exposed": "server" in exposed,
            "aligned": bool(direct_connect.get("serverCommandExposed")) == ("server" in exposed),
        },
        "direct_connect_open_surface": {
            "classification": "runtime-direct-connect-open-help-alignment",
            "runtime_exposed": bool(direct_connect.get("openCommandExposed")),
            "help_exposed": "open" in exposed,
            "aligned": bool(direct_connect.get("openCommandExposed")) == ("open" in exposed),
        },
        "ssh_remote_surface": {
            "classification": "runtime-ssh-help-alignment",
            "runtime_exposed": bool(ssh_remote.get("commandExposed")),
            "help_exposed": "ssh" in exposed,
            "aligned": bool(ssh_remote.get("commandExposed")) == ("ssh" in exposed),
        },
        "assistant_surface": {
            "classification": "runtime-assistant-help-alignment",
            "runtime_exposed": bool(assistant.get("commandExposed")),
            "help_exposed": "assistant" in exposed,
            "aligned": bool(assistant.get("commandExposed")) == ("assistant" in exposed),
        },
        "remote_manifest_surface": {
            "classification": "runtime-remote-manifest-status-alignment",
            "runtime_available": bool(remote.get("bridgeAvailable")),
            "manifest_status": manifest_status.get("remote"),
            "aligned": (
                manifest_status.get("remote") == "wired"
                if bool(remote.get("bridgeAvailable"))
                else manifest_status.get("remote") == "disabled"
            ),
        },
        "assistant_manifest_surface": {
            "classification": "runtime-assistant-manifest-status-alignment",
            "runtime_exposed": bool(assistant.get("commandExposed")),
            "manifest_status": manifest_status.get("assistant"),
            "aligned": (
                manifest_status.get("assistant") == "wired"
                if bool(assistant.get("commandExposed"))
                else manifest_status.get("assistant") == "disabled"
            ),
        },
    }

    unresolved = [
        name for name, detail in classifications.items() if not detail["aligned"]
    ]
    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "platform_command_surface_audit_failed": unresolved,
                    "classifications": classifications,
                    "exposed": sorted(exposed),
                    "runtime": {
                        "directConnect": direct_connect,
                        "sshRemote": ssh_remote,
                        "remote": remote,
                        "assistant": assistant,
                        "manifestStatus": manifest_status,
                    },
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
    }


def run_command_gap_audit() -> dict[str, object]:
    static_commands = list_static_program_commands()
    exposed_commands = list_exposed_program_commands()
    exposed_canonical = {entry.split("|")[0] for entry in exposed_commands}
    static_canonical = [entry.split("|")[0] for entry in static_commands]
    dormant = sorted({cmd for cmd in static_canonical if cmd not in exposed_canonical})
    return {
        "static_defined": sorted(set(static_canonical)),
        "exposed": exposed_commands,
        "dormant_or_gated": dormant,
    }


def run_dormant_command_audit() -> dict[str, object]:
    text = MAIN_TSX.read_text(errors="ignore")
    command_patterns = {
        "up": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('up')",
            "handler": "import('src/cli/up.js')",
        },
        "rollback": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('rollback [target]')",
            "handler": "import('src/cli/rollback.js')",
        },
        "log": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('log')",
            "handler": "await import('./cli/handlers/ant.js')",
        },
        "error": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('error')",
            "handler": "await import('./cli/handlers/ant.js')",
        },
        "export": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('export')",
            "handler": "await import('./cli/handlers/ant.js')",
        },
        "task": {
            "guard": '("external" as string) === \'ant\'',
            "anchor": "program.command('task')",
            "handler": "await import('./cli/handlers/ant.js')",
        },
    }
    classifications: dict[str, dict[str, object]] = {}
    for command, patterns in command_patterns.items():
        guard_present = patterns["guard"] in text
        anchor_present = patterns["anchor"] in text
        handler_present = patterns["handler"] in text
        ant_only_compiled_out = guard_present and anchor_present and handler_present
        classifications[command] = {
            "guard_present": guard_present,
            "anchor_present": anchor_present,
            "handler_present": handler_present,
            "classification": "ant-only-compiled-out"
            if ant_only_compiled_out
            else "unknown",
        }

    unresolved = [
        command
        for command, detail in classifications.items()
        if detail["classification"] != "ant-only-compiled-out"
    ]
    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "unresolved_dormant_commands": unresolved,
                    "classifications": classifications,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    result: dict[str, object] = {
        "status": "ok",
        "classifications": classifications,
    }
    if os.environ.get("MOSSENSRC_SMOKE_INCLUDE_RUNTIME") == "1":
        result["runtime"] = runtime
    return result


def run_maintenance_command_audit() -> dict[str, object]:
    main_text = MAIN_TSX.read_text(errors="ignore")
    util_text = (ROOT / "cli" / "handlers" / "util.tsx").read_text(errors="ignore")
    update_text = (ROOT / "cli" / "update.ts").read_text(errors="ignore")
    exposure = {
        name: probe_command_exposure(name)
        for name in ("setup-token", "install", "update")
    }

    classifications = {
        "setup-token": {
            "exposed": exposure["setup-token"]["exposed"],
            "anchor_present": "program.command('setup-token')" in main_text,
            "handler_present": "setupTokenHandler" in main_text,
            "custom_backend_branch_present": "isCustomBackendEnabled()" in util_text
            and "MOSSEN_CODE_CUSTOM_API_KEY" in util_text
            and "MOSSEN_CODE_CUSTOM_AUTH_TOKEN" in util_text
            and "MOSSEN_CODE_CUSTOM_HEADERS" in util_text,
            "oauth_flow_absent": "ConsoleOAuthFlow" not in util_text,
            "hosted_adapter_guidance_present": "Built-in account token setup is disabled in Mossen mainline."
            in util_text
            and "MOSSEN_CODE_ENABLE_HOSTED_AUTH_ADAPTER=1" in util_text,
            "classification": "backend-credential-bootstrap-hardcut",
        },
        "install": {
            "exposed": exposure["install"]["exposed"],
            "anchor_present": "program.command('install [target]')" in main_text,
            "handler_present": "installHandler" in main_text,
            "setup_bootstrap_present": "await import('../../setup.js')" in util_text,
            "installer_command_present": "await import('../../commands/install.js')" in util_text,
            "classification": "side-effectful-native-installer",
        },
        "update": {
            "exposed": exposure["update"]["exposed"],
            "anchor_present": "program.command('update')" in main_text,
            "handler_present": "await update();" in main_text,
            "doctor_diagnostic_present": "getDoctorDiagnostic()" in update_text,
            "native_installer_present": "installLatestNative(" in update_text,
            "package_updater_present": "installOrUpdateMossenPackage(" in update_text,
            "classification": "side-effectful-updater",
        },
    }

    unresolved = [
        name
        for name, detail in classifications.items()
        if not detail["exposed"]
        or not detail["anchor_present"]
        or not detail["handler_present"]
        or (
            name == "setup-token"
            and (
                not detail["custom_backend_branch_present"]
                or not detail["oauth_flow_absent"]
                or not detail["hosted_adapter_guidance_present"]
            )
        )
        or (
            name == "install"
            and (
                not detail["setup_bootstrap_present"]
                or not detail["installer_command_present"]
            )
        )
        or (
            name == "update"
            and (
                not detail["doctor_diagnostic_present"]
                or not detail["native_installer_present"]
                or not detail["package_updater_present"]
            )
        )
    ]
    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "unresolved_maintenance_commands": unresolved,
                    "classifications": classifications,
                    "exposure": exposure,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
        "exposure": exposure,
    }


def run_auth_command_audit() -> dict[str, object]:
    auth_help = normalize_output(run_cmd([CLI, "auth", "--help"]))
    login_help = normalize_output(run_cmd([CLI, "auth", "login", "--help"]))
    logout_help = normalize_output(run_cmd([CLI, "auth", "logout", "--help"]))
    login_proc = run_cmd_full([CLI, "auth", "login"], timeout=20)
    logout_proc = run_cmd_full([CLI, "auth", "logout"], timeout=20)
    login_output = normalize_output((login_proc.stdout or "") + (login_proc.stderr or ""))
    logout_output = normalize_output((logout_proc.stdout or "") + (logout_proc.stderr or ""))

    login_gate = "Built-in account flow is disabled in Mossen. Configure custom backend credentials instead."
    logout_note = "Custom backend mode does not keep a separate built-in account session."

    result = {
        "status": "ok",
        "auth_help_exposed": all(
            snippet in auth_help
            for snippet in ("login [options]", "logout", "status [options]")
        ),
        "login": {
            "exposed": "auth login [options]" in login_help,
            "returncode": login_proc.returncode,
            "gated": login_gate in login_output,
            "classification": "mossen-disabled-built-in-account-flow",
        },
        "logout": {
            "exposed": "auth logout [options]" in logout_help,
            "returncode": logout_proc.returncode,
            "no_op": logout_note in logout_output,
            "classification": "custom-backend-noop-first-party-logout",
        },
    }

    if (
        not result["auth_help_exposed"]
        or not result["login"]["exposed"]
        or result["login"]["returncode"] != 1
        or not result["login"]["gated"]
        or not result["logout"]["exposed"]
        or result["logout"]["returncode"] != 0
        or not result["logout"]["no_op"]
    ):
        raise RuntimeError(
            json.dumps(
                {
                    "auth_command_audit_failed": result,
                    "auth_help": auth_help,
                    "login_help": login_help,
                    "login_output": login_output[:1200],
                    "logout_help": logout_help,
                    "logout_output": logout_output[:1200],
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return result


def run_interactive_auth_gate_smoke() -> dict[str, object]:
    env = os.environ.copy()
    env.update(
        {
            "MOSSEN_CODE_USE_CUSTOM_BACKEND": "1",
            "MOSSEN_CODE_CUSTOM_BASE_URL": "https://gateway.example",
            "MOSSEN_CODE_CUSTOM_API_KEY": "sk-custom",
        }
    )
    proc = subprocess.run(
        [
            "bun",
            "-e",
            "import { call as loginCall } from './commands/login/login.tsx'; "
            "import { call as logoutCall } from './commands/logout/logout.tsx'; "
            "let loginMessage = null; let loginDisplay = null; "
            "await loginCall((message, options) => { loginMessage = message; loginDisplay = options?.display ?? null; }, {}); "
            "const logoutNode = await logoutCall(); "
            "console.log(JSON.stringify({"
            "loginMessage,"
            "loginDisplay,"
            "logoutText: logoutNode?.props?.children ?? null"
            "}));",
        ],
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=30,
        env=env,
    )
    output = normalize_output((proc.stdout or "").strip())
    result = json.loads(output)

    expected_login_messages = {
        "Mossen does not use a built-in account flow on this branch. Configure backend credentials with MOSSEN_CODE_CUSTOM_BASE_URL plus MOSSEN_CODE_CUSTOM_API_KEY or MOSSEN_CODE_CUSTOM_AUTH_TOKEN. If you intentionally wrap an external hosted service, enable that Mossen adapter explicitly with MOSSEN_CODE_ENABLE_HOSTED_AUTH_ADAPTER=1 and inject its credentials there.",
        "Mossen 当前分支不使用内置账号流程。请通过 MOSSEN_CODE_CUSTOM_BASE_URL 加 MOSSEN_CODE_CUSTOM_API_KEY 或 MOSSEN_CODE_CUSTOM_AUTH_TOKEN 配置后端凭据。如果确实要封装外部托管服务，请显式设置 MOSSEN_CODE_ENABLE_HOSTED_AUTH_ADAPTER=1，并在该 Mossen adapter 中注入凭据。",
    }
    expected_logout_messages = {
        "Custom backend mode does not keep a separate built-in account session.",
        "当前已启用自定义后端模式。该模式下没有独立的内置账号会话可退出。",
    }
    if (
        proc.returncode != 0
        or result.get("loginDisplay") != "system"
        or result.get("loginMessage") not in expected_login_messages
        or result.get("logoutText") not in expected_logout_messages
    ):
        raise RuntimeError(
            json.dumps(
                {
                    "interactive_auth_gate_smoke_failed": result,
                    "expectedLoginMessages": sorted(expected_login_messages),
                    "expectedLogoutMessages": sorted(expected_logout_messages),
                    "returncode": proc.returncode,
                    "stdout": output[:1200],
                    "stderr": normalize_output(proc.stderr or "")[:1200],
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classification": "runtime-custom-backend-local-jsx-auth-gates",
        **result,
    }


