def run_worktree_resume_runtime_audit() -> dict[str, object]:
    helper_text = (ROOT / "utils" / "worktreeResume.ts").read_text(errors="ignore")
    selector_text = (ROOT / "components" / "LogSelector.tsx").read_text(
        errors="ignore"
    )
    resume_text = (ROOT / "commands" / "resume" / "resume.tsx").read_text(
        errors="ignore"
    )
    startup_resume_text = (
        ROOT / "screens" / "ResumeConversation.tsx"
    ).read_text(errors="ignore")
    cross_project_resume_text = (
        ROOT / "utils" / "crossProjectResume.ts"
    ).read_text(errors="ignore")
    probe_script = """
import {
  getWorktreeMetadataSuffix,
  isLogInCurrentWorktree,
  prioritizeCurrentWorktreeLogs,
  selectPreferredCurrentWorktreeLog,
} from './utils/worktreeResume.ts'
import { mkdirSync, mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { setCwdState, setOriginalCwd } from './bootstrap/state.ts'
import { exitRestoredWorktree, restoreWorktreeForResume } from './utils/sessionRestore.ts'
import { getCurrentWorktreeObservabilitySnapshot, restoreWorktreeSession } from './utils/worktree.ts'
import { checkCrossProjectResume } from './utils/crossProjectResume.ts'

const currentCwd = '/private/tmp/repo/.mossen/worktrees/feature-x'
const logs = [
  {
    sessionId: 'other-1',
    projectPath: '/tmp/repo/.mossen/worktrees/feature-y',
    worktreeSession: { worktreeName: 'feature-y' },
  },
  {
    sessionId: 'current-1',
    projectPath: currentCwd,
    worktreeSession: { worktreeName: 'feature-x' },
  },
  {
    sessionId: 'other-2',
    projectPath: '/tmp/repo',
  },
  {
    sessionId: 'current-2',
    projectPath: currentCwd,
    worktreeSession: { worktreeName: 'feature-x' },
  },
]

const root = mkdtempSync(join(tmpdir(), 'mossensrc-resume-worktree-switch-'))
const original = join(root, 'repo')
const worktreeA = join(root, 'repo/.mossen/worktrees/feature-a')
const worktreeB = join(root, 'repo/.mossen/worktrees/feature-b')
mkdirSync(worktreeA, { recursive: true })
mkdirSync(worktreeB, { recursive: true })

process.chdir(worktreeA)
setCwdState(worktreeA)
setOriginalCwd(original)
restoreWorktreeSession({
  originalCwd: original,
  worktreePath: worktreeA,
  worktreeName: 'feature-a',
  worktreeBranch: 'worktree-feature-a',
  originalBranch: 'main',
  sessionId: 'resume-switch-current',
})
exitRestoredWorktree()
restoreWorktreeForResume({
  originalCwd: original,
  worktreePath: worktreeB,
  worktreeName: 'feature-b',
  worktreeBranch: 'worktree-feature-b',
  originalBranch: 'main',
  sessionId: 'resume-switch-target',
})

process.env.USER_TYPE = 'external'
const crossProject = checkCrossProjectResume(
  {
    sessionId: 'resume-target-1234',
    projectPath: '/tmp/other-project',
  },
  true,
  ['/tmp/repo', '/tmp/repo/.mossen/worktrees/feature-x'],
)

console.log(JSON.stringify({
  currentFlags: {
    current: isLogInCurrentWorktree(logs[1], currentCwd),
    other: isLogInCurrentWorktree(logs[0], currentCwd),
  },
  prioritized: prioritizeCurrentWorktreeLogs(logs, currentCwd).map(log => log.sessionId),
  duplicateChoice: selectPreferredCurrentWorktreeLog(logs.slice(0, 2), currentCwd)?.sessionId ?? null,
  suffixes: {
    current: getWorktreeMetadataSuffix(logs[1], currentCwd),
    namedOther: getWorktreeMetadataSuffix(logs[0], currentCwd),
    pathOther: getWorktreeMetadataSuffix(logs[2], currentCwd),
  },
  startupSwitch: {
    cwd: process.cwd(),
    snapshot: getCurrentWorktreeObservabilitySnapshot(),
  },
  crossProject,
}))
"""
    proc = run_cmd_full([RUN_BUN, "-e", probe_script], timeout=120)
    output = normalize_output((proc.stdout or "") + (proc.stderr or ""))
    runtime_present = False
    runtime_details: dict[str, object] = {}
    if proc.returncode == 0 and proc.stdout.strip():
        runtime_details = json.loads(proc.stdout.strip())
        runtime_present = (
            runtime_details.get("currentFlags") == {"current": True, "other": False}
            and runtime_details.get("prioritized")
            == ["current-1", "current-2", "other-1", "other-2"]
            and runtime_details.get("duplicateChoice") == "current-1"
            and (runtime_details.get("suffixes") or {}).get("namedOther")
            == " · feature-y"
            and (runtime_details.get("suffixes") or {}).get("pathOther")
            == " · /tmp/repo"
            and (runtime_details.get("suffixes") or {}).get("current")
            in {" · current worktree", " · 当前工作树"}
            and str(((runtime_details.get("startupSwitch") or {}).get("cwd"))).endswith(
                "/repo/.mossen/worktrees/feature-b"
            )
            and ((runtime_details.get("startupSwitch") or {}).get("snapshot") or {}).get("name")
            == "feature-b"
            and ((runtime_details.get("crossProject") or {}).get("command") or "").endswith(
                "mossen --resume resume-target-1234"
            )
        )

    classifications = {
        "worktree_resume_helper_extraction": {
            "classification": "runtime-worktree-resume-helper-extraction",
            "source_present": "export function isLogInCurrentWorktree(" in helper_text
            and "export function prioritizeCurrentWorktreeLogs(" in helper_text
            and "export function selectPreferredCurrentWorktreeLog(" in helper_text
            and "export function getWorktreeMetadataSuffix(" in helper_text,
            "runtime_present": runtime_present,
        },
        "worktree_resume_selector_consumes_helper": {
            "classification": "runtime-worktree-resume-selector-consumes-helper",
            "source_present": "from '../utils/worktreeResume.js'" in selector_text
            and "prioritizeCurrentWorktreeLogs(filtered, currentCwd);" in selector_text
            and "getWorktreeMetadataSuffix(log, currentCwd)" in selector_text,
            "runtime_present": runtime_present,
        },
        "worktree_resume_title_prefers_current_worktree": {
            "classification": "runtime-worktree-resume-title-prefers-current-worktree",
            "source_present": "selectPreferredCurrentWorktreeLog(titleMatches, getOriginalCwd())"
            in resume_text
            and "const preferredTitleMatch = selectPreferredCurrentWorktreeLog("
            in resume_text,
            "runtime_present": runtime_present,
        },
        "worktree_resume_startup_switch_alignment": {
            "classification": "runtime-worktree-resume-startup-switch-alignment",
            "source_present": "exitRestoredWorktree();" in startup_resume_text
            and "restoreWorktreeForResume(result_3.worktreeSession);" in startup_resume_text,
            "runtime_present": runtime_present,
        },
        "worktree_cross_project_resume_command_alignment": {
            "classification": "runtime-worktree-cross-project-resume-command-alignment",
            "source_present": "&& mossen --resume ${sessionId}" in cross_project_resume_text,
            "runtime_present": runtime_present,
        },
    }

    unresolved = []
    for key, detail in classifications.items():
        for field, value in detail.items():
            if field == "classification":
                continue
            if not value:
                unresolved.append(key)
                break

    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "worktree_resume_runtime_audit_failed": sorted(set(unresolved)),
                    "classifications": classifications,
                    "runtime": runtime_details,
                    "output": output[:2400],
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
        "runtime": runtime_details,
    }


