def run_worktree_parallel_stability_runtime_audit() -> dict[str, object]:
    worktree_text = (ROOT / "utils" / "worktree.ts").read_text(errors="ignore")
    probe_script = """
import { execFileSync } from 'child_process'
import { existsSync, mkdirSync, utimesSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { setCwdState } from './bootstrap/state.ts'
import {
  cleanupStaleAgentWorktrees,
  hasWorktreeChanges,
  restoreWorktreeSession,
} from './utils/worktree.ts'

function git(args, cwd) {
  return execFileSync('git', args, {
    cwd,
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
  }).trim()
}

const root = tmpdir() + '/mossensrc-worktree-parallel-' + Math.random().toString(16).slice(2)
mkdirSync(root, { recursive: true })
const remote = join(root, 'origin.git')
const repo = join(root, 'repo')
mkdirSync(repo, { recursive: true })

git(['init', '--bare', remote])
git(['init', '-b', 'main', repo])
git(['config', 'user.name', 'Smoke User'], repo)
git(['config', 'user.email', 'smoke@example.com'], repo)
writeFileSync(join(repo, 'README.md'), 'root\\n')
git(['add', 'README.md'], repo)
git(['commit', '-m', 'init'], repo)
git(['remote', 'add', 'origin', remote], repo)
git(['push', '-u', 'origin', 'main'], repo)

mkdirSync(join(repo, '.mossen', 'worktrees'), { recursive: true })

const currentWorktree = join(repo, '.mossen', 'worktrees', 'agent-a1234567')
const staleWorktree = join(repo, '.mossen', 'worktrees', 'agent-a7654321')

git(['worktree', 'add', currentWorktree, '-b', 'worktree-agent-a1234567', 'main'], repo)
git(['worktree', 'add', staleWorktree, '-b', 'worktree-agent-a7654321', 'main'], repo)
git(['push', '-u', 'origin', 'worktree-agent-a1234567'], currentWorktree)
git(['push', '-u', 'origin', 'worktree-agent-a7654321'], staleWorktree)

const currentHead = git(['rev-parse', 'HEAD'], currentWorktree)
const cleanState = await hasWorktreeChanges(currentWorktree, currentHead)

const nestedCurrentDir = join(currentWorktree, 'nested')
mkdirSync(nestedCurrentDir, { recursive: true })
process.chdir(nestedCurrentDir)
setCwdState(nestedCurrentDir)
restoreWorktreeSession(null)

const oldDate = new Date(Date.now() - 40 * 24 * 60 * 60 * 1000)
utimesSync(currentWorktree, oldDate, oldDate)
utimesSync(staleWorktree, oldDate, oldDate)

const removed = await cleanupStaleAgentWorktrees(new Date())
const currentExistsAfterCleanup = existsSync(currentWorktree)
const staleExistsAfterCleanup = existsSync(staleWorktree)

writeFileSync(join(currentWorktree, 'dirty.txt'), 'dirty\\n')
const dirtyState = await hasWorktreeChanges(currentWorktree, currentHead)

console.log(
  JSON.stringify({
    cleanState,
    dirtyState,
    removed,
    currentExistsAfterCleanup,
    staleExistsAfterCleanup,
  }),
)
"""
    proc = run_cmd_full(["bun", "-e", probe_script], timeout=180)
    output = normalize_output((proc.stdout or "") + (proc.stderr or ""))
    runtime_present = False
    runtime_details: dict[str, object] = {}
    if proc.returncode == 0 and proc.stdout.strip():
      runtime_details = json.loads(proc.stdout.strip())
      runtime_present = runtime_details == {
          "cleanState": False,
          "dirtyState": True,
          "removed": 1,
          "currentExistsAfterCleanup": True,
          "staleExistsAfterCleanup": False,
      }

    classifications = {
        "worktree_cleanup_skips_current_cwd": {
            "classification": "runtime-worktree-cleanup-skips-current-cwd",
            "source_present": "canonicalizeComparablePath(" in worktree_text
            and "const resolvedCurrentCwd = await canonicalizeComparablePath(getCwd())"
            in worktree_text
            and "const currentCwdInsideWorktree =" in worktree_text
            and "resolvedCurrentCwd.startsWith(resolvedWorktreePath + sep)" in worktree_text,
            "runtime_present": runtime_present,
        },
        "worktree_cleanup_removes_clean_stale_sibling": {
            "classification": "runtime-worktree-cleanup-removes-clean-stale-sibling",
            "source_present": "cleanupStaleAgentWorktrees(" in worktree_text
            and "status', '--porcelain', '-uno'" in worktree_text
            and "'rev-list', '--max-count=1', 'HEAD', '--not', '--remotes'" in worktree_text,
            "runtime_present": runtime_present,
        },
        "worktree_change_detection_clean_dirty": {
            "classification": "runtime-worktree-change-detection-clean-dirty",
            "source_present": "export async function hasWorktreeChanges(" in worktree_text
            and "['status', '--porcelain']" in worktree_text
            and "['rev-list', '--count', `${headCommit}..HEAD`]" in worktree_text,
            "runtime_present": runtime_present,
        },
    }

    unresolved = []
    for key, detail in classifications.items():
        for field, value in detail.items():
            if field == "classification":
                continue
            if not value:
                unresolved.append(key)
                break

    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "worktree_parallel_stability_runtime_audit_failed": sorted(
                        set(unresolved)
                    ),
                    "classifications": classifications,
                    "runtime": runtime_details,
                    "output": output[:2400],
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
        "runtime": runtime_details,
    }


