def run_lsp_binary_guard_audit() -> dict[str, object]:
    manager_text = (ROOT / "services" / "lsp" / "LSPServerManager.ts").read_text(
        errors="ignore"
    )
    notification_text = (
        ROOT / "hooks" / "notifs" / "useLspInitializationNotification.tsx"
    ).read_text(errors="ignore")

    runtime_proc = subprocess.run(
        [
            RUN_BUN,
            "-e",
            "import { initializeLspServerManager, waitForInitialization, getInitializationStatus } from './services/lsp/manager.ts'; "
            "initializeLspServerManager(); "
            "await waitForInitialization(); "
            "console.log(JSON.stringify(getInitializationStatus()));",
        ],
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=45,
        check=True,
    )
    runtime = json.loads(normalize_output(runtime_proc.stdout.strip()))

    result = {
        "status": "ok",
        "classification": "runtime-lsp-binary-guard",
        "source_present": "import { isBinaryInstalled } from '../../utils/binaryCheck.js'" in manager_text
        and "const binaryInstalled = await isBinaryInstalled(config.command)" in manager_text
        and "Skipping LSP server" in manager_text
        and "binary '" in manager_text
        and "function shouldSuppressLspNotification(errorMessage: string): boolean {" in notification_text
        and "Suppressing user-visible LSP notification for soft failure" in notification_text
        and "normalized.includes(\"enoent\")" in notification_text,
        "runtime_present": runtime == {"status": "success"},
    }

    if not result["source_present"] or not result["runtime_present"]:
        raise RuntimeError(
            json.dumps(
                {
                    "lsp_binary_guard_audit_failed": result,
                    "runtime": runtime,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return result


def run_custom_backend_auth_runtime_audit() -> dict[str, object]:
    env = os.environ.copy()
    env.update(
        {
            "MOSSEN_CODE_CUSTOM_API_KEY": " ",
            "MOSSEN_CODE_CUSTOM_AUTH_TOKEN": " ",
            "MOSSEN_CODE_CUSTOM_HEADERS": " ",
        }
    )

    status_proc = subprocess.run(
        [CLI, "auth", "status"],
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=30,
        env=env,
    )
    text_proc = subprocess.run(
        [CLI, "auth", "status", "--text"],
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=30,
        env=env,
    )

    status_output = normalize_output(status_proc.stdout or "")
    text_output = normalize_output((text_proc.stdout or "") + (text_proc.stderr or ""))
    parsed = json.loads(status_output)

    result = {
        "status": "ok",
        "classification": "runtime-custom-backend-auth-truthfulness",
        "status_exit_code": status_proc.returncode,
        "text_exit_code": text_proc.returncode,
        "logged_in": parsed.get("loggedIn"),
        "credentials_configured": parsed.get("credentialsConfigured"),
        "auth_capability": ((parsed.get("capabilities") or {}).get("auth")),
        "text_note_present": "Auth note: no custom backend auth headers are currently configured." in text_output,
        "text_state_present": "Credential state: missing" in text_output,
    }

    if (
        result["status_exit_code"] != 0
        or result["text_exit_code"] != 0
        or result["logged_in"] is not False
        or result["credentials_configured"] is not False
        or result["auth_capability"] is not False
        or not result["text_note_present"]
        or not result["text_state_present"]
    ):
        raise RuntimeError(
            json.dumps(
                {
                    "custom_backend_auth_runtime_audit_failed": result,
                    "status_stdout": status_output[:1200],
                    "status_stderr": normalize_output(status_proc.stderr or "")[:1200],
                    "text_output": text_output[:1200],
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return result


def run_custom_backend_auth_ui_runtime_audit() -> dict[str, object]:
    hook_text = (ROOT / "hooks" / "useApiKeyVerification.ts").read_text(errors="ignore")
    notifications_text = (
        ROOT / "components" / "PromptInput" / "Notifications.tsx"
    ).read_text(errors="ignore")
    errors_text = (ROOT / "services" / "api" / "errors.ts").read_text(errors="ignore")

    def bun_eval(code: str, extra_env: dict[str, str]) -> dict[str, object]:
        env = os.environ.copy()
        env.update(extra_env)
        proc = subprocess.run(
            ["bun", "-e", code],
            cwd=ROOT,
            text=True,
            capture_output=True,
            timeout=30,
            env=env,
            check=True,
        )
        return json.loads(normalize_output(proc.stdout.strip()))

    missing_runtime = bun_eval(
        "import { getInitialApiKeyVerificationStatus } from './hooks/useApiKeyVerification.ts'; "
        "import { getAuthStatusNotice } from './components/PromptInput/Notifications.tsx'; "
        "import { getInvalidApiKeyErrorMessage, getAuthenticationFailedErrorMessage } from './services/api/errors.ts'; "
        "console.log(JSON.stringify({"
        "status:getInitialApiKeyVerificationStatus(),"
        "notice:getAuthStatusNotice('missing'),"
        "invalid:getInvalidApiKeyErrorMessage(),"
        "generic:getAuthenticationFailedErrorMessage('401 Unauthorized')"
        "}));",
        {
            "MOSSEN_CODE_USE_CUSTOM_BACKEND": "1",
            "MOSSEN_CODE_CUSTOM_BASE_URL": "https://gateway.example",
            "MOSSEN_CODE_CUSTOM_API_KEY": " ",
            "MOSSEN_CODE_CUSTOM_AUTH_TOKEN": " ",
            "MOSSEN_CODE_CUSTOM_HEADERS": " ",
        },
    )
    configured_runtime = bun_eval(
        "import { getInitialApiKeyVerificationStatus } from './hooks/useApiKeyVerification.ts'; "
        "import { getAuthStatusNotice } from './components/PromptInput/Notifications.tsx'; "
        "import { getInvalidApiKeyErrorMessage, getTokenRevokedErrorMessage } from './services/api/errors.ts'; "
        "console.log(JSON.stringify({"
        "status:getInitialApiKeyVerificationStatus(),"
        "notice:getAuthStatusNotice('invalid'),"
        "invalid:getInvalidApiKeyErrorMessage(),"
        "revoked:getTokenRevokedErrorMessage()"
        "}));",
        {
            "MOSSEN_CODE_USE_CUSTOM_BACKEND": "1",
            "MOSSEN_CODE_CUSTOM_BASE_URL": "https://gateway.example",
            "MOSSEN_CODE_CUSTOM_API_KEY": "sk-custom",
            "MOSSEN_CODE_CUSTOM_NAME": "Gateway Runtime",
        },
    )

    classifications = {
        "custom_backend_verification_runtime": {
            "classification": "runtime-custom-backend-verification-status",
            "source_present": "export function getInitialApiKeyVerificationStatus(): VerificationStatus {" in hook_text
            and "if (isCustomBackendEnabled()) {" in hook_text
            and "return hasCustomBackendAuth() ? 'valid' : 'missing'" in hook_text,
            "runtime_present": missing_runtime == {
                "status": "missing",
                "notice": "Custom backend auth missing · Configure custom backend credentials",
                "invalid": "API Error: Custom backend auth missing · Configure custom backend credentials",
                "generic": "API Error: Custom backend auth missing · Configure custom backend credentials · 401 Unauthorized",
            },
        },
        "custom_backend_notification_runtime": {
            "classification": "runtime-custom-backend-auth-notice-surface",
            "source_present": "export function getAuthStatusNotice(apiKeyStatus: VerificationStatus): string | null {" in notifications_text
            and "return apiKeyStatus === 'missing'" in notifications_text
            and "Configure custom backend credentials" in notifications_text,
            "runtime_present": configured_runtime.get("notice")
            == "Gateway Runtime auth failed · Check custom backend credentials",
        },
        "custom_backend_error_surface_runtime": {
            "classification": "runtime-custom-backend-auth-error-surface",
            "source_present": "export function getInvalidApiKeyErrorMessage(): string {" in errors_text
            and "export function getAuthenticationFailedErrorMessage(" in errors_text
            and "getCustomBackendAuthSummary()" in errors_text,
            "runtime_present": configured_runtime.get("invalid")
            == "API Error: Gateway Runtime authentication failed · Check custom backend credentials",
        },
        "custom_backend_revoked_token_runtime": {
            "classification": "runtime-custom-backend-token-expiry-surface",
            "source_present": "export function getTokenRevokedErrorMessage(): string {" in errors_text
            and "auth token expired" in errors_text,
            "runtime_present": configured_runtime.get("revoked")
            == "API Error: Gateway Runtime auth token expired · Refresh custom backend credentials",
        },
    }

    unresolved = []
    for key, detail in classifications.items():
        for field, value in detail.items():
            if field == "classification":
                continue
            if not value:
                unresolved.append(key)
                break

    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "custom_backend_auth_ui_runtime_audit_failed": sorted(set(unresolved)),
                    "classifications": classifications,
                    "missing_runtime": missing_runtime,
                    "configured_runtime": configured_runtime,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
    }


def run_custom_backend_integration_gate_runtime_audit() -> dict[str, object]:
    # SKIPPED post-bridge-removal (2026-04-25): audit asserted bridge subsystem
    # is the gating point between custom backend and hosted features. Bridge
    # is gone; the gate simplification is now the absence of bridge itself.
    # Re-validate via P0-08 harness L4 (config) layer.
    return {
        "status": "skipped",
        "reason": "bridge subsystem removed; gate now implicit",
    }
    bridge_enabled_text = (ROOT / "bridge" / "bridgeEnabled.ts").read_text(errors="ignore")
    bridge_types_text = (ROOT / "bridge" / "types.ts").read_text(errors="ignore")
    bridge_main_text = (ROOT / "bridge" / "bridgeMain.ts").read_text(errors="ignore")
    assistant_text = (ROOT / "platform" / "assistantRuntime.ts").read_text(errors="ignore")
    team_text = (ROOT / "platform" / "teamMemoryRuntime.ts").read_text(errors="ignore")
    chrome_runtime_text = (ROOT / "platform" / "chromeRuntime.ts").read_text(errors="ignore")
    chrome_notification_text = (
        ROOT / "hooks" / "useChromeExtensionNotification.tsx"
    ).read_text(errors="ignore")
    chrome_onboarding_text = (
        ROOT / "components" / "MossenInChromeOnboarding.tsx"
    ).read_text(errors="ignore")
    chrome_command_text = (
        ROOT / "commands" / "chrome" / "chrome.tsx"
    ).read_text(errors="ignore")
    main_text = (ROOT / "main.tsx").read_text(errors="ignore")
    platform_runtime_text = (ROOT / "platform" / "runtime.ts").read_text(
        errors="ignore"
    )
    chrome_surface_source_present = (
        "getChromeIntegrationUrls" in chrome_runtime_text
        and "hasChromeCommandAccess" in chrome_runtime_text
        and "hasConfiguredChromeIntegrationUrls" in (
            ROOT / "utils" / "customBackend.ts"
        ).read_text(errors="ignore")
        and "Chrome extension not detected" in chrome_notification_text
        and (
            "Chrome integration is not enabled for the current provider or backend configuration."
            in chrome_notification_text
            or "in Chrome is not enabled for the current provider or backend configuration."
            in chrome_command_text
        )
        and (
            "CHROME_DOCS_URL" in chrome_onboarding_text
            or "CHROME_EXTENSION_URL" in chrome_onboarding_text
        )
    )

    def bun_eval(code: str, extra_env: dict[str, str]) -> dict[str, object]:
        env = os.environ.copy()
        env.update(extra_env)
        proc = subprocess.run(
            [RUN_BUN, "-e", code],
            cwd=ROOT,
            text=True,
            capture_output=True,
            timeout=45,
            env=env,
            check=True,
        )
        return json.loads(normalize_output(proc.stdout.strip()))

    runtime = bun_eval(
        "import { getBridgeDisabledReason } from './bridge/bridgeEnabled.ts'; "
        "import { getAssistantRuntimeSnapshot } from './platform/assistantRuntime.ts'; "
        "import { getTeamMemoryRuntimeSnapshot } from './platform/teamMemoryRuntime.ts'; "
        "import { getChromeRuntimeSnapshot } from './platform/chromeRuntime.ts'; "
        "import { setChromeFlagOverride } from './bootstrap/state.ts'; "
        "import { getChromeExtensionNotificationSurface } from './hooks/useChromeExtensionNotification.tsx'; "
        "process.argv.push('--chrome'); "
        "setChromeFlagOverride(true); "
        "console.log(JSON.stringify({"
        "bridge:await getBridgeDisabledReason(),"
        "assistant:await getAssistantRuntimeSnapshot(),"
        "team:getTeamMemoryRuntimeSnapshot(),"
        "chrome:await getChromeRuntimeSnapshot(),"
        "chromeNotice:await getChromeExtensionNotificationSurface()"
        "}));",
        {
            "MOSSEN_CODE_USE_CUSTOM_BACKEND": "1",
            "MOSSEN_CODE_CUSTOM_BASE_URL": "https://gateway.example",
            "MOSSEN_CODE_CUSTOM_API_KEY": "sk-custom",
            "MOSSEN_CODE_CHROME_EXTENSION_URL": "https://platform.mossen.test/chrome",
            "MOSSEN_CODE_CHROME_FOCUS_TAB_URL_BASE": "https://platform.mossen.test/chrome/tab/",
            "MOSSEN_CODE_CHROME_PERMISSIONS_URL": "https://platform.mossen.test/chrome/permissions",
            "MOSSEN_CODE_CHROME_RECONNECT_URL": "https://platform.mossen.test/chrome/reconnect",
            "MOSSEN_CODE_CHROME_DOCS_URL": "https://platform.mossen.test/docs/chrome",
            "MOSSEN_INTERNAL_FC_OVERRIDES": json.dumps({"tengu_herring_clock": True}),
        },
    )

    classifications = {
        "custom_backend_remote_gate_runtime": {
            "classification": "runtime-custom-backend-remote-gate-surface",
            "source_present": "Remote Control requires the hosted bridge service and is unavailable on the current custom backend." in bridge_enabled_text
            and "Remote Control requires hosted bridge credentials and is unavailable on the current provider or backend configuration." in bridge_types_text
            and "Remote Control - Connect your local environment to the hosted bridge service" in bridge_main_text,
            "runtime_present": runtime.get("bridge")
            in {
                "Remote Control requires the hosted bridge service and is unavailable on the current custom backend.",
                "Remote Control is not available in this build.",
            },
        },
        "custom_backend_assistant_gate_runtime": {
            "classification": "runtime-custom-backend-assistant-gate-surface",
            "source_present": "Assistant attach requires hosted bridge sessions and is unavailable on the current custom backend." in assistant_text
            and "feature('KAIROS') && !isCustomBackendEnabled()" in main_text
            and "entry.id === 'assistant' && !assistant.commandExposed" in platform_runtime_text,
            "runtime_present": runtime.get("assistant", {}).get("statusReason")
            in {
                "Assistant attach requires hosted bridge sessions and is unavailable on the current custom backend.",
                "Assistant mode is not available in this build.",
            },
        },
        "custom_backend_team_memory_gate_runtime": {
            "classification": "runtime-custom-backend-team-memory-gate-surface",
            "source_present": "Team memory sync requires the hosted sync service and is unavailable on the current provider/auth path." in team_text,
            "runtime_present": runtime.get("team", {}).get("enabled") is True
            and runtime.get("team", {}).get("syncAvailable") is False
            and runtime.get("team", {}).get("statusReason")
            in {
                "Team memory sync requires the hosted sync service and is unavailable on the current provider/auth path.",
                "Team memory build flag is disabled in the current runtime.",
            },
        },
        "custom_backend_chrome_surface_runtime": {
            "classification": "runtime-custom-backend-chrome-surface",
            "source_present": chrome_surface_source_present,
            "runtime_present": runtime.get("chrome", {}).get("installUrl") is None
            and runtime.get("chrome", {}).get("statusReason")
            == "Chrome integration is not enabled for the current provider or backend configuration."
            and runtime.get("chromeNotice", {}).get("message")
            in {
                "Chrome integration is not enabled for the current provider or backend configuration.",
                "当前 provider 或后端配置未启用 Chrome 集成。",
            },
        },
    }

    unresolved = []
    for key, detail in classifications.items():
        for field, value in detail.items():
            if field == "classification":
                continue
            if not value:
                unresolved.append(key)
                break

    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "custom_backend_integration_gate_runtime_audit_failed": sorted(
                        set(unresolved)
                    ),
                    "classifications": classifications,
                    "runtime": runtime,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
    }


def run_local_git_runtime_audit() -> dict[str, object]:
    local_git_text = (
        ROOT / "platform" / "localGitRuntime.ts"
    ).read_text(errors="ignore")
    auth_handler_text = (
        ROOT / "cli" / "handlers" / "auth.ts"
    ).read_text(errors="ignore")
    doctor_text = (
        ROOT / "screens" / "Doctor.tsx"
    ).read_text(errors="ignore")
    platform_check_text = (
        ROOT / "scripts" / "platform_check.ts"
    ).read_text(errors="ignore")
    manifest_text = (
        ROOT / "platform" / "manifest.ts"
    ).read_text(errors="ignore")
    runtime_types_text = (
        ROOT / "platform" / "runtimeTypes.ts"
    ).read_text(errors="ignore")
    commit_push_pr_text = (
        ROOT / "commands" / "commit-push-pr.ts"
    ).read_text(errors="ignore")
    gh_auth_text = (
        ROOT / "utils" / "github" / "ghAuthStatus.ts"
    ).read_text(errors="ignore")

    proc = subprocess.run(
        [
            RUN_BUN,
            "-e",
            "import { getLocalGitRuntimeSnapshot } from './platform/localGitRuntime.ts'; "
            "console.log(JSON.stringify(await getLocalGitRuntimeSnapshot()));",
        ],
        cwd=ROOT,
        text=True,
        capture_output=True,
        timeout=45,
        check=True,
    )
    runtime = json.loads(normalize_output(proc.stdout.strip()))

    expected_local_pr_ready = (
        runtime.get("gitInstalled") is True
        and runtime.get("ghInstalled") is True
        and runtime.get("ghAuthenticated") is True
        and runtime.get("commitPushPrCommandExposed") is True
    )
    expected_status_reason = None
    if not runtime.get("gitInstalled"):
        expected_status_reason = (
            "Git CLI is not installed, so local repository workflows are unavailable."
        )
    elif not runtime.get("ghInstalled"):
        expected_status_reason = (
            "GitHub CLI is not installed. Local git still works, but PR automation is unavailable."
        )
    elif not runtime.get("ghAuthenticated"):
        expected_status_reason = (
            "GitHub CLI is not authenticated. Local git still works, but PR automation is unavailable until `gh auth login`."
        )

    classifications = {
        "local_git_runtime_surface": {
            "classification": "runtime-local-git-surface",
            "source_present": "export async function getLocalGitRuntimeSnapshot()" in local_git_text
            and "const commitPushPrCommandExposed = existsSync(COMMIT_PUSH_PR_COMMAND)" in local_git_text
            and "const localPrReady =" in local_git_text
            and "GitHub CLI is not authenticated. Local git still works, but PR automation is unavailable until `gh auth login`." in local_git_text
            and "Bash(git push:*)" in commit_push_pr_text
            and "Bash(gh pr create:*)" in commit_push_pr_text
            and "export async function getGhAuthStatus()" in gh_auth_text
            and "gh auth token" in gh_auth_text
            and "name: 'localGit'" in platform_check_text
            and "id: 'local-git'" in manifest_text
            and "| 'local-git'" in runtime_types_text,
            "runtime_present": runtime.get("localGitReady") == runtime.get("gitInstalled")
            and runtime.get("localPrReady") == expected_local_pr_ready
            and runtime.get("statusReason") == expected_status_reason
            and isinstance(runtime.get("gitPath"), (str, type(None)))
            and isinstance(runtime.get("ghPath"), (str, type(None))),
        },
        "local_git_status_surface": {
            "classification": "runtime-local-git-auth-status-surface",
            "source_present": "Platform core: git=${output.platformCore.localGitReady ? 'ready' : 'off'}" in auth_handler_text
            and "pr=${output.platformCore.localPrReady ? 'ready' : output.platformCore.ghInstalled ? output.platformCore.ghAuthenticated ? 'command-only' : 'gh-auth-missing' : 'gh-missing'}" in auth_handler_text
            and "Local git note: ${platformRuntime.localGit.statusReason}" in auth_handler_text,
            "runtime_present": True,
        },
        "local_git_doctor_surface": {
            "classification": "runtime-local-git-doctor-surface",
            "source_present": "└ Local git: git {platformRuntime.localGit.gitInstalled ? \"ready\" : \"missing\"}" in doctor_text
            and "commit-push-pr {platformRuntime.localGit.commitPushPrCommandExposed ? \"yes\" : \"no\"}" in doctor_text
            and "Local git note: {platformRuntime.localGit.statusReason}" in doctor_text,
            "runtime_present": True,
        },
    }

    unresolved = []
    for key, detail in classifications.items():
        for field, value in detail.items():
            if field == "classification":
                continue
            if not value:
                unresolved.append(key)
                break

    if unresolved:
        raise RuntimeError(
            json.dumps(
                {
                    "local_git_runtime_audit_failed": sorted(set(unresolved)),
                    "classifications": classifications,
                    "runtime": runtime,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "classifications": classifications,
        "runtime": runtime,
    }


