         "workflowUsesBootstrapRunner:WORKFLOW_CONTENT.includes('MOSSEN_CODE_GITHUB_RUNNER_URL'),"
         "reviewWorkflowUsesBootstrapRunner:CODE_REVIEW_PLUGIN_WORKFLOW_CONTENT.includes('MOSSEN_CODE_GITHUB_RUNNER_URL'),"
         "workflowUsesCustomBaseUrlVar:WORKFLOW_CONTENT.includes('MOSSEN_CODE_CUSTOM_BASE_URL: ${{ vars.MOSSEN_CODE_CUSTOM_BASE_URL }}'),"
         "reviewWorkflowUsesCustomBaseUrlVar:CODE_REVIEW_PLUGIN_WORKFLOW_CONTENT.includes('MOSSEN_CODE_CUSTOM_BASE_URL: ${{ vars.MOSSEN_CODE_CUSTOM_BASE_URL }}'),"
         "workflowUsesBootstrapVariable:WORKFLOW_CONTENT.includes('MOSSEN_CODE_GITHUB_ACTION_BOOTSTRAP_URL'),"
