            "const adjusted=adjustParamsForNonStreaming({max_tokens:100000,thinking:{type:'enabled',budget_tokens:90000}},MAX_NON_STREAMING_TOKENS); "
            "console.log(JSON.stringify({"
            f"opus3:getMaxOutputTokensForModel('{MOSSEN_OPUS_3}'),"
            f"sonnet46Override:getMaxOutputTokensForModel('{MOSSEN_SONNET_4_6}'),"
            "adjusted:{max_tokens:adjusted.max_tokens,budget:adjusted.thinking?.budget_tokens ?? null}"
            "}))",
            {"MOSSEN_CODE_MAX_OUTPUT_TOKENS": "5000"},
