            "]}); "
            "const run=async()=>{"
            "const trigger=evaluateTimeBasedTrigger([assistant,user],'repl_main_thread'); "
            "const noSource=evaluateTimeBasedTrigger([assistant,user],undefined); "
            "const result=await microcompactMessages([assistant,user],undefined,'repl_main_thread'); "
            "const content=result.messages[1].message.content; "
            "console.log(JSON.stringify({"
