            "setLastEffectiveSystemPromptAssembly({baseSource:'default',overlaySources:['x'],itemCount:1}); "
            "setAfkModeHeaderLatched(true); "
            "setFastModeHeaderLatched(true); "
            "setCacheEditingHeaderLatched(true); "
