            "clearRegisteredHooks(); "
            "registerHookCallbacks({InstructionsLoaded:[{matcher:'compact',hooks:[{type:'callback',timeout:1,internal:true,callback:async(input)=>{events.push({reason:input.load_reason,path:input.file_path,type:input.memory_type});return {};}}]}]}); "
            "await getMemoryFiles(); "
            "events.length=0; "
            "resetGetMemoryFilesCache('compact'); "
            "await getMemoryFiles(); "
            "await new Promise(resolve=>setTimeout(resolve,50)); "
            "console.log(JSON.stringify({"
            "eventCount:events.length,"
            "reasons:[...new Set(events.map(event=>event.reason))].sort(),"
            "hasProjectCompact:events.some(event=>event.reason==='compact'&&event.path===join(tempDir,'MOSSEN.md')&&event.type==='Project'),"
            "hasUserCompact:events.some(event=>event.reason==='compact'&&event.type==='User')"
            "})); "
            "} finally { "
            "clearRegisteredHooks(); "
            "rmSync(tempDir,{recursive:true,force:true}); "
            "}",
