def run_personal_memory_runtime_audit() -> dict[str, object]:
    paths_text = (ROOT / "memdir" / "paths.ts").read_text(errors="ignore")
    memdir_text = (ROOT / "memdir" / "memdir.ts").read_text(errors="ignore")
    attachments_text = (ROOT / "utils" / "attachments.ts").read_text(
        errors="ignore"
    )
    conversation_recovery_text = (
        ROOT / "utils" / "conversationRecovery.ts"
    ).read_text(errors="ignore")
    session_restore_text = (
        ROOT / "utils" / "sessionRestore.ts"
    ).read_text(errors="ignore")
    main_text = (ROOT / "main.tsx").read_text(errors="ignore")
    extractor_text = (
        ROOT / "services" / "extractMemories" / "extractMemories.ts"
    ).read_text(errors="ignore")
    stop_hooks_text = (ROOT / "query" / "stopHooks.ts").read_text(errors="ignore")
    housekeeping_text = (
        ROOT / "utils" / "backgroundHousekeeping.ts"
    ).read_text(errors="ignore")
    print_text = (ROOT / "cli" / "print.ts").read_text(errors="ignore")

    def bun_eval(env: dict[str, str]) -> dict[str, object]:
        proc = subprocess.run(
            [
                RUN_BUN,
                "-e",
                (
                    "import { setIsInteractive } from './bootstrap/state.ts'; "
                    "import { isAutoMemoryEnabled, isExtractModeActive, getAutoMemPath } from './memdir/paths.ts'; "
                    "import { loadMemoryPrompt } from './memdir/memdir.ts'; "
                    "setIsInteractive(true); "
                    "const prompt = await loadMemoryPrompt(); "
                    "console.log(JSON.stringify({"
                    "auto: isAutoMemoryEnabled(), "
                    "extract: isExtractModeActive(), "
                    "path: getAutoMemPath(), "
                    "promptLoaded: prompt !== null, "
                    "hasPastSearch: prompt?.includes('Session transcript logs') === true && prompt?.includes('.jsonl') === true"
                    "}));"
                ),
            ],
            cwd=ROOT,
            text=True,
            capture_output=True,
            timeout=60,
            env=env,
            check=True,
        )
        return json.loads(normalize_output(proc.stdout.strip()))

    with tempfile.TemporaryDirectory(prefix="mossensrc-personal-memory.") as tmp:
        tmp_path = Path(tmp)
        memory_dir = tmp_path / "memory"
        memory_dir.mkdir(parents=True)
        env = os.environ.copy()
        env.update(
            {
                "MOSSEN_CODE_USE_CUSTOM_BACKEND": "1",
                "MOSSEN_CODE_CUSTOM_BASE_URL": "http://127.0.0.1:9",
                "MOSSEN_CODE_CUSTOM_MODEL": "qwen3.6-plus",
                "MOSSEN_COWORK_MEMORY_PATH_OVERRIDE": str(memory_dir) + os.sep,
                "MOSSEN_CONFIG_DIR": str(tmp_path / "config"),
            }
        )
        env.pop("MOSSEN_CODE_DISABLE_AUTO_MEMORY", None)
        enabled = bun_eval(env)

        disabled_env = env.copy()
        disabled_env["MOSSEN_CODE_DISABLE_AUTO_MEMORY"] = "1"
        disabled = bun_eval(disabled_env)

    source_present = (
        "MOSSEN_CODE_ENABLE_EXTRACT_MEMORIES" in paths_text
        and "isCustomBackendEnabled() ||" in paths_text
        and "MOSSEN_CODE_ENABLE_PAST_CONTEXT_SEARCH" in memdir_text
        and "isCustomBackendEnabled() ||" in memdir_text
        and "MOSSEN_CODE_ENABLE_RELEVANT_MEMORY_PREFETCH" in attachments_text
        and "isCustomBackendEnabled() ||" in attachments_text
        and "buildRelevantMemoryRecallInput" in attachments_text
        and "MEMORY_RESUME_PROMPT_RE" in attachments_text
        and "Recall recent project handoff" in attachments_text
        and "projectPath: chain[0]?.cwd" in conversation_recovery_text
        and "restoreProjectPathForResume" in session_restore_text
        and "setProjectRoot(cwd)" in session_restore_text
        and "adoptSessionProjectDirectory" in main_text
        and "setProjectRoot(cwd)" in main_text
        and "isExtractModeActive()" in extractor_text
        and "feature('EXTRACT_MEMORIES') &&" not in stop_hooks_text
        and "feature('EXTRACT_MEMORIES') && isExtractModeActive()" not in print_text
        and "initExtractMemories()" in housekeeping_text
    )
    runtime_present = (
        enabled == {
            "auto": True,
            "extract": True,
            "path": str(memory_dir) + os.sep,
            "promptLoaded": True,
            "hasPastSearch": True,
        }
        and disabled["auto"] is False
        and disabled["extract"] is False
        and disabled["promptLoaded"] is False
    )
    if not source_present or not runtime_present:
        raise RuntimeError(
            json.dumps(
                {
                    "personal_memory_runtime_failed": {
                        "source_present": source_present,
                        "runtime_present": runtime_present,
                        "enabled": enabled,
                        "disabled": disabled,
                    }
                },
                ensure_ascii=False,
                indent=2,
            )
        )
    return {
        "status": "ok",
        "enabled": enabled,
        "disabled": disabled,
    }


def run_dependency_audit() -> dict[str, object]:
    builtins = set(
        json.loads(
            subprocess.check_output(
                ["node", "-e", "console.log(JSON.stringify(require('module').builtinModules))"],
                cwd=ROOT,
                text=True,
            )
        )
    )
    missing: dict[str, int] = {}
    resolution_cache: dict[str, bool] = {}
    for path in ROOT.rglob("*"):
        if path.suffix not in {".ts", ".tsx", ".js", ".mjs", ".cjs", ".mts", ".cts"}:
            continue
        if {"node_modules", "dist", "vendor", ".git"} & set(path.parts):
            continue
        try:
            text = path.read_text(errors="ignore")
        except OSError:
            continue
        for match in IMPORT_RE.finditer(text):
            spec = match.group(1)
            if (
                spec.startswith((".", "/", "src/", "file:", "bun:"))
                or spec.endswith(".node")
                or spec == "type-fest"
            ):
                continue
            if spec.startswith("@"):
                pkg = "/".join(spec.split("/")[:2])
            else:
                pkg = spec.split("/")[0]
            if pkg in builtins or pkg.startswith("node:"):
                continue
            if spec not in resolution_cache:
                proc = subprocess.run(
                    ["bun", "-e", f"await import({spec!r})"],
                    cwd=ROOT,
                    text=True,
                    capture_output=True,
                )
                resolution_cache[spec] = proc.returncode == 0
            if not resolution_cache[spec]:
                missing[spec] = missing.get(spec, 0) + 1
    if missing:
        raise RuntimeError(
            json.dumps({"missing_packages": missing}, ensure_ascii=False, indent=2)
        )
    return {"status": "ok", "checked_commands": "imports"}


def run_external_bridge_boundary_audit() -> dict[str, object]:
    mossen_sdk_text = (ROOT / "services" / "api" / "mossenSdk.ts").read_text(errors="ignore")
    dxt_helpers_text = (ROOT / "utils" / "dxt" / "helpers.ts").read_text(errors="ignore")
    chrome_adapter_text = (
        ROOT / "utils" / "mossenInChrome" / "chromeMcpAdapter.ts"
    ).read_text(errors="ignore")
    sandbox_runtime_text = (
        ROOT / "utils" / "sandbox" / "sandboxRuntimeAdapter.ts"
    ).read_text(errors="ignore")
    chrome_skill_text = (
        ROOT / "skills" / "bundled" / "mossenInChrome.ts"
    ).read_text(errors="ignore")

    source_checks = {
        "provider_missing_bridge_sanitized": "sanitizeExternalProviderCause" in mossen_sdk_text
        and "loadExternalProviderPackage(" in mossen_sdk_text
        and "Mossen external provider bridge is not installed." in mossen_sdk_text,
        "plugin_missing_bridge_sanitized": "sanitizeExternalMcpbCause" in dxt_helpers_text
        and "Mossen plugin bridge is not installed." in dxt_helpers_text
        and ("Mossen " + "MCPB" + " bridge is not installed.") not in dxt_helpers_text,
        "sandbox_missing_bridge_sanitized": "sanitizeExternalSandboxRuntimeCause"
        in sandbox_runtime_text
        and "Mossen sandbox runtime bridge is not installed." in sandbox_runtime_text,
        "chrome_allowed_tools_no_default_bridge_require": "tryLoadExternalChromeMcp"
        in chrome_adapter_text
        and "FALLBACK_CHROME_MCP_TOOL_NAMES" in chrome_adapter_text
        and "getMossenChromeMcpAllowedToolNames(" in chrome_skill_text,
    }

    runtime_script = r"""
const externalText = (...codes) => String.fromCharCode(...codes)
const forbidden = [
  externalText(64, 97, 110, 116, 104, 114, 111, 112, 105, 99, 45, 97, 105),
  externalText(64, 97, 110, 116),
  externalText(65, 110, 116, 104, 114, 111, 112, 105, 99),
  externalText(67, 108, 97, 117, 100, 101),
]

function assertNoForbidden(label, value) {
  const text = String(value)
  const leaked = forbidden.filter(token => text.includes(token))
  if (leaked.length > 0) {
    throw new Error(`${label} leaked external bridge token(s): ${JSON.stringify(leaked)} in ${text}`)
  }
}

async function bridgeProbe(label, expectedBridgeMessage, fn) {
  try {
    await fn()
    return { label, state: 'bridge-installed-or-not-required' }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    if (!message.includes(expectedBridgeMessage)) {
      assertNoForbidden(label, message)
      return { label, state: 'other-error', message }
    }
    assertNoForbidden(label, message)
    return { label, state: 'missing-bridge', message }
  }
}

const provider = await import('./services/api/mossenSdk.ts')
const plugin = await import('./utils/dxt/helpers.ts')
const sandbox = await import('./utils/sandbox/sandboxRuntimeAdapter.ts')
const chrome = await import('./utils/mossenInChrome/chromeMcpAdapter.ts')
await import('./skills/bundled/mossenInChrome.ts')

const probes = []
probes.push(await bridgeProbe(
  'provider-default',
  'Mossen external provider bridge is not installed',
  () => new provider.MossenProviderSDK({}),
))
probes.push(await bridgeProbe(
  'provider-bedrock',
  'Mossen Bedrock provider bridge is not installed',
  () => provider.loadMossenBedrockProviderSDK(),
))
probes.push(await bridgeProbe(
  'provider-foundry',
  'Mossen Foundry provider bridge is not installed',
  () => provider.loadMossenFoundryProviderSDK(),
))
probes.push(await bridgeProbe(
  'provider-vertex',
  'Mossen Vertex provider bridge is not installed',
  () => provider.loadMossenVertexProviderSDK(),
))
probes.push(await bridgeProbe(
  'plugin-bundle',
  'Mossen plugin bridge is not installed',
  () => plugin.validateManifest({}),
))

const sandboxDeps = sandbox.MossenSandboxRuntimeManager.checkDependencies({})
for (const error of sandboxDeps.errors ?? []) {
  assertNoForbidden('sandbox-runtime', error)
}
const chromeTools = chrome.getMossenChromeMcpAllowedToolNames('mossen-in-chrome')
if (!Array.isArray(chromeTools)) {
  throw new Error('Chrome bridge allowed tools did not return an array')
}

console.log(JSON.stringify({ probes, sandboxDeps, chromeToolCount: chromeTools.length }))
"""
    runtime_proc = run_cmd_full([RUN_BUN, "-e", runtime_script], timeout=60)
    runtime_stdout = normalize_output(runtime_proc.stdout.strip())
    runtime_stderr = normalize_output(runtime_proc.stderr.strip())
    runtime_present = runtime_proc.returncode == 0
    runtime_details = {}
    if runtime_present and runtime_stdout:
        runtime_details = json.loads(runtime_stdout)

    if not all(source_checks.values()) or not runtime_present:
        raise RuntimeError(
            json.dumps(
                {
                    "external_bridge_boundary_audit_failed": {
                        "source_checks": source_checks,
                        "runtime_returncode": runtime_proc.returncode,
                        "runtime_stdout": runtime_stdout[:2000],
                        "runtime_stderr": runtime_stderr[:2000],
                    }
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    return {
        "status": "ok",
        "source_checks": source_checks,
        "runtime": runtime_details,
    }


def run_statusline_smoke() -> dict[str, str]:
    proc, fd = spawn_cli()
    try:
        _, startup_output = wait_for_text(
            fd,
            ["❯", "Welcome back!", "Unable"],
            20,
        )
        if is_mossen_backend_connectivity_gate(startup_output):
            return {
                "status": "gated",
                "classification": "statusline-tui-hard-cut-backend-connectivity-required",
            }
        write_line(fd, "/statusline\n")
        deadline = time.time() + 40
        data = ""
        matched = None
        compact_patterns = [
            "当前statusLine配置",
            "CurrentstatusLinesetup",
            "NostatusLineisconfiguredrightnow",
            "未配置statusLine",
            "/Users/allen/.mossen/statusline.sh",
            "~/.mossen/settings.json",
        ]
        while time.time() < deadline:
            remaining = max(0.1, deadline - time.time())
            readable, _, _ = select.select([fd], [], [], remaining)
            if not readable:
                continue
            try:
                chunk = os.read(fd, 4096).decode("utf-8", errors="ignore")
            except OSError:
                break
            if not chunk:
                break
            respond_to_terminal_queries(fd, chunk)
            data += chunk
            compact = re.sub(r"\s+", "", normalize_output(data))
            for pattern in compact_patterns:
                if pattern in compact:
                    matched = pattern
                    break
            if matched:
                break
        if not matched:
            raise TimeoutError(
                "Timed out waiting for statusline UI\n--- output ---\n" + data
            )
        terminate_process_tree(proc)
        return {"status": "ok"}
    finally:
        try:
            os.close(fd)
        except OSError:
            pass
        terminate_process_tree(proc)


def run_chat_smoke() -> dict[str, str]:
    last_error: Exception | None = None
    for _attempt in range(2):
        proc, fd = spawn_cli()
        try:
            _, startup_output = wait_for_text(
                fd,
                ["❯", "Welcome back!", "欢迎回来！", "Unable"],
                25,
            )
            if is_mossen_backend_connectivity_gate(startup_output):
                return {
                    "status": "gated",
                    "classification": "chat-tui-hard-cut-backend-connectivity-required",
                }
            write_line(fd, "你好\n")
            wait_for_text(
                fd,
                [
                    # 弱化为通用关键字 (model 偶发用不同 greeting 变体)
                    "你好",  # 任一含 "你好" 的回复都接受
                    "Hello",
                    "Hi",
                    "我可以",
                    "可以帮",
                    "Mossen",
                ],
                60,
            )
            exit_cli(proc, fd)
            return {"status": "ok"}
        except Exception as exc:
            last_error = exc
            time.sleep(0.2)
        finally:
            try:
                os.close(fd)
            except OSError:
                pass
            if proc.poll() is None:
                proc.kill()
    assert last_error is not None
    raise last_error


def run_chrome_smoke() -> dict[str, object]:
    help_text = run_cmd([CLI, "--help"])
    if not re.search(r"\n\s+chrome(?:\s|\[)", help_text):
        return {
            "status": "disabled",
            "classification": "chrome-tui-custom-backend-disabled-by-default",
        }

    proc, fd = spawn_cli()
    try:
        _, startup_output = wait_for_text(
            fd,
            ["❯", "Welcome back!", "Unable"],
            35,
        )
        if is_mossen_backend_connectivity_gate(startup_output):
            return {
                "status": "gated",
                "classification": "chrome-tui-hard-cut-backend-connectivity-required",
            }
        write_line(fd, "/chrome\n")
        deadline = time.time() + 45
        data = ""
        matched = None
        output = ""
        patterns = [
            "MossenBrowserIntegration(Beta)",
            "InstallChromeextension",
            "Managepermissions",
            "Reconnectextension",
            "Enabledbydefault",
            "mossen--chrome",
        ]
        while time.time() < deadline:
            remaining = max(0.1, deadline - time.time())
            readable, _, _ = select.select([fd], [], [], remaining)
            if not readable:
                continue
            try:
                chunk = os.read(fd, 4096).decode("utf-8", errors="ignore")
            except OSError:
                break
            if not chunk:
                break
            respond_to_terminal_queries(fd, chunk)
            data += chunk
            output = normalize_output(data)
            compact = re.sub(r"\s+", "", output)
            for pattern in patterns:
                if pattern in compact:
                    matched = pattern
                    break
            if matched:
                break
        if not matched:
            raise TimeoutError(
                "Timed out waiting for Chrome UI\n--- output ---\n" + data
            )
        terminate_process_tree(proc)
        return {
            "status": "ok",
            "matched": matched,
            "extension_detected": "Extension: Not detected" not in output
            and "Extension:Notdetected" not in re.sub(r"\s+", "", output),
            "host_only": "InstallChromeextension" in re.sub(r"\s+", "", output)
            or "Extension:Notdetected" in re.sub(r"\s+", "", output),
        }
    finally:
        try:
            os.close(fd)
        except OSError:
            pass
        terminate_process_tree(proc)


def run_doctor_smoke() -> dict[str, str]:
    last_error: Exception | None = None
    for attempt in range(2):
        master_fd, slave_fd = pty.openpty()
        proc = subprocess.Popen(
            [CLI, "doctor"],
            cwd=ROOT,
            stdin=slave_fd,
            stdout=slave_fd,
            stderr=slave_fd,
            close_fds=True,
            start_new_session=True,
        )
        register_smoke_pid(proc.pid)
        os.close(slave_fd)
        try:
            try:
                wait_for_text(
                    master_fd,
                    [
                        "Doctor",
                        "诊断信息",
                        "Platform Core",
                        "平台核心",
                        "Checking",
                        "正在检查",
                        "Press",
                        "按",
                        "continue",
                        "继续",
                    ],
                    20,
                )
            except TimeoutError as exc:
                code = proc.poll()
                if attempt == 0 and code is not None:
                    last_error = exc
                    continue
                raise
            deadline = time.time() + 5
            while time.time() < deadline:
                code = proc.poll()
                if code is not None:
                    if code != 0:
                        raise RuntimeError(f"doctor exited with code {code}")
                    return {"status": "ok"}
                time.sleep(0.2)
            terminate_process_tree(proc)
            return {"status": "rendered"}
        finally:
            try:
                os.close(master_fd)
            except OSError:
                pass
            terminate_process_tree(proc)
    if last_error is not None:
        raise last_error
    raise RuntimeError("doctor smoke exhausted retries without a recorded failure")


def run_plugin_list_smoke(expected_count: Optional[int] = None) -> dict[str, object]:
    output = run_cmd([CLI, "plugin", "list"], timeout=60)
    normalized = normalize_output(output)
    if "Installed plugins:" not in normalized and "No plugins installed" not in normalized:
        raise RuntimeError(f"unexpected plugin list output\n--- output ---\n{normalized[:1200]}")
    detected = count_bullet_entries(normalized)
    if expected_count is not None and "Installed plugins:" in normalized and detected < expected_count:
        raise RuntimeError(
            f"plugin list count mismatch: expected at least {expected_count}, got {detected}\n--- output ---\n{normalized[:1200]}"
        )
    return {
        "status": "ok",
        "count": detected,
        "has_plugins": "Installed plugins:" in normalized,
    }


def run_mcp_list_smoke() -> dict[str, object]:
    output = run_cmd([CLI, "mcp", "list"], timeout=60)
    normalized = normalize_output(output)
    health_check_ran = (
        "Checking MCP server health" in normalized
        or "正在检查 MCP 服务器健康状态" in normalized
    )
    healthy = (
        "Connected" in normalized
        or "已连接" in normalized
        or "No MCP servers configured" in normalized
        or "未配置 MCP 服务器" in normalized
    )
    if not health_check_ran and not healthy:
        raise RuntimeError(f"unexpected mcp list output\n--- output ---\n{normalized[:1200]}")
    connected = len(re.findall(r"✓ (Connected|已连接)", normalized))
    failed = len(re.findall(r"[✗xX] ", normalized))
    return {
        "status": "ok",
        "connected": connected,
        "failed": failed,
        "health_check_ran": health_check_ran,
    }


def run_agents_smoke(expected_count: Optional[int] = None) -> dict[str, object]:
    output = run_cmd([CLI, "agents"], timeout=30)
    normalized = normalize_output(output)
    match = re.search(r"(\d+)\s+active agents", normalized)
    if not match:
        raise RuntimeError(f"unexpected agents output\n--- output ---\n{normalized[:1200]}")
    active = int(match.group(1))
    if expected_count is not None and active != expected_count:
        raise RuntimeError(
            f"agents count mismatch: expected {expected_count}, got {active}\n--- output ---\n{normalized[:1200]}"
        )
    return {
        "status": "ok",
        "active": active,
        "has_builtin_section": "Built-in agents:" in normalized,
        "has_user_section": "User agents:" in normalized,
    }


def run_session_resume_smoke(session_dir: Path) -> dict[str, object]:
    before_files = {str(path) for path in list_session_files(session_dir)}
    create_phrase = "session smoke create"
    continue_phrase = "session smoke continue"
    resume_phrase = "session smoke resume"

    create_proc = run_cmd_full(
        [CLI, "-p", f"Reply with exactly: {create_phrase}"],
        timeout=90,
    )
    create_output = normalize_output(create_proc.stdout or "").strip()
    create_error = normalize_output(create_proc.stderr or "").strip()
    create_combined = (create_output + "\n" + create_error).strip()
    hard_cut_backend_error = (
        "API Error: Custom backend mode requires MOSSEN_CODE_CUSTOM_BASE_URL to be set."
    )
    forbidden_guidance = LEGACY_BRAND_FORBIDDEN_GUIDANCE

    if create_proc.returncode != 0:
        if (
            hard_cut_backend_error in create_combined
            and all(token not in create_combined for token in forbidden_guidance)
        ):
            return {
                "status": "ok",
                "classification": "runtime-session-recovery-hard-cut-custom-backend-config-required",
                "returncode": create_proc.returncode,
            }
        raise RuntimeError(
            json.dumps(
                {
                    "session_create_failed": {
                        "returncode": create_proc.returncode,
                        "stdout": create_output[:1200],
                        "stderr": create_error[:1200],
                    },
                    "expectedHardCut": hard_cut_backend_error,
                    "forbiddenGuidance": forbidden_guidance,
                },
                ensure_ascii=False,
                indent=2,
            )
        )

    expect_contains(create_output, create_phrase, "session create")

    after_files = list_session_files(session_dir)
    session_file = find_new_session_file(before_files, after_files)
    session_id = session_file.stem

    continue_output = run_cmd(
        [CLI, "-p", "--continue", f"Reply with exactly: {continue_phrase}"],
        timeout=90,
    )
    expect_contains(continue_output, continue_phrase, "session continue")

    resume_output = run_cmd(
        [CLI, "-p", "--resume", session_id, f"Reply with exactly: {resume_phrase}"],
        timeout=90,
    )
    expect_contains(resume_output, resume_phrase, "session resume")

    line_count = sum(1 for _ in session_file.open())
    return {
        "status": "ok",
        "session_id": session_id,
        "transcript": str(session_file),
        "lines": line_count,
    }


def build_domain_matrix(
    platform_check: dict[str, object],
    auth_status: dict[str, object],
    report: dict[str, object],
) -> dict[str, dict[str, object]]:
    runtime = platform_check.get("runtime") or {}
    checks = {
        check["name"]: check
        for check in platform_check.get("checks", [])
        if isinstance(check, dict) and "name" in check
    }
    platform_core = auth_status.get("platformCore") or {}
    feature_gates = runtime.get("featureGates") or {}

    def check_ok(name: str) -> bool:
        value = checks.get(name) or {}
        return bool(value.get("ok"))

    matrix = {
        "provider": {
            "state": "usable" if check_ok("provider") else "broken",
            "detail": runtime.get("provider"),
        },
        "direct-connect": {
            "state": "disabled"
            if not runtime.get("directConnect", {}).get("featureEnabled")
            else "snapshot-missing"
            if (
                (not runtime.get("directConnect", {}).get("serverRuntimeAvailable")
                 or not runtime.get("directConnect", {}).get("openRuntimeAvailable"))
                and not runtime.get("directConnect", {}).get("recoverableFromLocalCache")
            )
            else "blocked"
            if (
                not runtime.get("directConnect", {}).get("serverRuntimeAvailable")
                or not runtime.get("directConnect", {}).get("openRuntimeAvailable")
            )
            else "available",
            "detail": {
                "runtime": runtime.get("directConnect"),
                "featureGates": {
                    "directConnect": feature_gates.get("directConnect"),
                },
                "commands": {
                    key: report["advanced_commands"]["probes"][key]
                    for key in ("server", "open")
                },
                "probe": report["direct_connect_probe"],
                "localRecovery": report["local_recovery_audit"],
            },
        },
        "ssh-remote": {
            "state": "disabled"
            if not runtime.get("sshRemote", {}).get("featureEnabled")
            else "snapshot-missing"
            if (
                (not runtime.get("sshRemote", {}).get("localTestAvailable")
                 or not runtime.get("sshRemote", {}).get("remoteSessionAvailable"))
                and not runtime.get("sshRemote", {}).get("recoverableFromLocalCache")
            )
            else "blocked"
            if (
                not runtime.get("sshRemote", {}).get("localTestAvailable")
                or not runtime.get("sshRemote", {}).get("remoteSessionAvailable")
            )
            else "available",
            "detail": {
                "runtime": runtime.get("sshRemote"),
                "featureGates": {
                    "sshRemote": feature_gates.get("sshRemote"),
                },
                "commands": {
                    "ssh": report["advanced_commands"]["probes"]["ssh"],
                },
                "probe": report["ssh_probe"],
                "localRecovery": report["local_recovery_audit"],
            },
        },
        "system-prompt": {
            "state": "usable" if check_ok("systemPrompt") else "broken",
            "detail": runtime.get("systemPrompt"),
        },
        "memory": {
            "state": "usable" if check_ok("memory") else "broken",
            "detail": runtime.get("memory"),
        },
        "compression": {
            "state": "usable" if check_ok("compression") else "broken",
            "detail": runtime.get("compression"),
        },
        "skills": {
            "state": "usable" if check_ok("skills") else "broken",
            "detail": runtime.get("skills"),
        },
        "security": {
            "state": "usable" if check_ok("security") else "broken",
            "detail": runtime.get("security"),
        },
        "plugins": {
            "state": "usable" if report["plugin_list"]["status"] == "ok" else "broken",
            "detail": {
                "runtime": runtime.get("plugins"),
                "smoke": report["plugin_list"],
            },
        },
        "mcp": {
            "state": "usable" if report["mcp_list"]["status"] == "ok" else "broken",
            "detail": {
                "runtime": runtime.get("mcp"),
                "smoke": report["mcp_list"],
            },
        },
        "agents": {
            "state": "usable" if report["agents"]["status"] == "ok" else "broken",
            "detail": {
                "runtime": runtime.get("agents"),
                "smoke": report["agents"],
                "sdk_cli_count": platform_core.get("activeAgents"),
            },
        },
        "sessions": {
            "state": "usable" if report["session_recovery"]["status"] == "ok" else "broken",
            "detail": {
                "runtime": runtime.get("sessions"),
                "smoke": report["session_recovery"],
            },
        },
        "remote": {
            "state": "available"
            if runtime.get("remote", {}).get("bridgeAvailable")
            else "gated"
            if runtime.get("remote", {}).get("policyAllowed")
            else "disabled",
            "detail": {
                "runtime": runtime.get("remote"),
                "featureGates": {
                    "directConnect": feature_gates.get("directConnect"),
                    "sshRemote": feature_gates.get("sshRemote"),
                    "bridgeMode": feature_gates.get("bridgeMode"),
                },
                "commands": {
                    key: report["advanced_commands"]["probes"][key]
                    for key in ("server", "ssh", "open")
                },
                "gate": report["remote_gate"],
            },
        },
        "chrome": {
            "state": "usable"
            if runtime.get("chrome", {}).get("extensionInstalled")
            else "host-ready"
            if runtime.get("chrome", {}).get("nativeHostInstalled")
            else "env-not-ready",
            "detail": {
                "runtime": runtime.get("chrome"),
                "smoke": report.get("chrome_tui"),
            },
        },
        "voice": {
            "state": "env-not-ready"
            if (
                not runtime.get("voice", {}).get("streamAvailable")
                or not runtime.get("voice", {}).get("recordingAvailable")
            )
            else "available"
            if not runtime.get("voice", {}).get("userEnabled")
            else "usable",
            "detail": runtime.get("voice"),
        },
        "team-memory": {
            "state": "disabled"
            if not runtime.get("teamMemory", {}).get("buildEnabled")
            else "gated"
            if not runtime.get("teamMemory", {}).get("enabled")
            else "local-only"
            if not runtime.get("teamMemory", {}).get("syncAvailable")
            else "usable",
            "detail": {
                "runtime": runtime.get("teamMemory"),
                "smoke": report.get("team_memory_probe"),
            },
        },
        "swarm": {
            "state": "idle" if not runtime.get("swarm", {}).get("teammate") else "usable",
            "detail": runtime.get("swarm"),
        },
        "assistant": {
            "state": "disabled"
            if not runtime.get("assistant", {}).get("featureEnabled")
            else "usable"
            if runtime.get("assistant", {}).get("attachAvailable")
            else "gated"
            if runtime.get("assistant", {}).get("discoveryAvailable")
            else "degraded",
            "detail": {
                "featureGates": {
                    "kairos": feature_gates.get("kairos"),
                    "bridgeMode": feature_gates.get("bridgeMode"),
                },
                "runtime": runtime.get("assistant"),
                "command": report["advanced_commands"]["probes"]["assistant"],
                "gate": report["assistant_gate"],
            },
        },
        "auto-mode": {
            "state": "gated"
            if not report["advanced_commands"]["probes"]["auto-mode"]["exposed"]
            else "available",
            "detail": {
                "featureGates": {
                    "transcriptClassifier": feature_gates.get("transcriptClassifier"),
                },
                "command": report["advanced_commands"]["probes"]["auto-mode"],
            },
        },
        "task": {
            "state": "gated"
            if not report["advanced_commands"]["probes"]["task"]["exposed"]
            else "available",
            "detail": {
                "featureGates": {
                    "kairos": feature_gates.get("kairos"),
                },
                "command": report["advanced_commands"]["probes"]["task"],
                "reason": "Task CLI is compiled out in the external build, and the ant-only handler module is not present in this source snapshot.",
            },
        },
    }
    return matrix


def _format_step_duration(seconds: float) -> str:
    if seconds < 60:
        return f"{seconds:.1f}s"
    minutes = int(seconds // 60)
    remaining = seconds - (minutes * 60)
    return f"{minutes}m{remaining:04.1f}s"


def _emit_smoke_progress(
    index: int,
    total: int,
    name: str,
    status: str,
    duration: Optional[float] = None,
    detail: Optional[str] = None,
) -> None:
    parts = [f"[{index:02d}/{total:02d}]", name, status]
    if duration is not None:
        parts.append(_format_step_duration(duration))
    if detail:
        parts.append(detail)
    print(" ".join(parts), file=sys.stderr, flush=True)


def _run_report_step(
    report: dict[str, object],
    index: int,
    total: int,
    name: str,
    fn,
) -> object:
    _emit_smoke_progress(index, total, name, "starting")
    started_at = time.perf_counter()
    try:
        value = fn()
    except Exception as exc:
        _emit_smoke_progress(
            index,
            total,
            name,
            "failed",
            time.perf_counter() - started_at,
            f"({type(exc).__name__}: {exc})",
        )
        raise
    duration = time.perf_counter() - started_at
    report[name] = value
    _emit_smoke_progress(index, total, name, "done", duration)
    return value


def _print_smoke_usage() -> None:
    print(
        "\n".join(
            [
                "Usage: python3 scripts/smoke_check.py [--only CHECK[,CHECK...]]",
                "",
                "Runs the full Mossen smoke suite by default.",
                "",
                "Options:",
                "  --help, -h       Show this help and exit.",
                "  --list           List available check names and exit.",
                "  --only CHECKS    Run only the named checks, comma-separated or repeated.",
                "",
                "Examples:",
                "  python3 scripts/smoke_check.py --only cloud_auth_runtime_audit",
                "  python3 scripts/smoke_check.py --only model_surface_runtime_audit,model_limits_runtime_audit",
            ]
        )
    )


def _parse_smoke_cli_args(argv: list[str]) -> tuple[list[str], bool]:
    only: list[str] = []
    list_checks = False
    index = 0
    while index < len(argv):
        arg = argv[index]
        if arg in ("--help", "-h"):
            _print_smoke_usage()
            raise SystemExit(0)
        if arg == "--list":
            list_checks = True
            index += 1
            continue
        if arg == "--only":
            index += 1
            if index >= len(argv):
                raise ValueError("--only requires at least one check name")
            only.extend(part for part in argv[index].split(",") if part)
            index += 1
            continue
        if arg.startswith("--only="):
            only.extend(part for part in arg.split("=", 1)[1].split(",") if part)
            index += 1
            continue
        raise ValueError(f"unknown smoke_check argument: {arg}")
    return only, list_checks


def main() -> int:
    report: dict[str, object] = {}
    only_names, list_checks = _parse_smoke_cli_args(sys.argv[1:])

    reap_stale_smoke_processes()
    def load_platform_check() -> dict[str, object]:
        return json.loads(run_cmd([RUN_BUN, "scripts/platform_check.ts"], timeout=60))

    def load_auth_status() -> dict[str, object]:
        auth_status = json.loads(run_cmd([CLI, "auth", "status"]))
        if auth_status.get("authMethod") == "custom_backend" and not auth_status.get(
            "protocol"
        ):
            raise RuntimeError("custom backend auth status missing protocol")
        if auth_status.get("authMethod") == "custom_backend":
            if "credentialsConfigured" not in auth_status:
                raise RuntimeError(
                    "custom backend auth status missing credentialsConfigured"
                )
            if auth_status.get("model") and "contextWindowTokens" not in auth_status:
                raise RuntimeError(
                    "custom backend auth status missing contextWindowTokens"
                )
            platform_core = auth_status.get("platformCore") or {}
            required = {
                "directConnectFeatureEnabled",
                "directConnectServerReady",
                "directConnectOpenReady",
                "sshFeatureEnabled",
                "sshLocalTestReady",
                "sshRemoteReady",
                "pluginCount",
                "mcpServerCount",
                "remoteAllowed",
                "remoteDisabledReason",
                "assistantCommandExposed",
                "chromeInstalled",
                "voiceAvailable",
                "teamMemoryEnabled",
                "activeAgents",
                "projectSessions",
                "swarmActive",
                "agentEntrypoint",
                "codeGuideAgent",
                "featureGates",
            }
            if not required.issubset(platform_core):
                raise RuntimeError(
                    "custom backend auth status missing extended platform core data"
                )
        return auth_status

