    if list_checks:
        print("\n".join(name for name, _fn in steps))
        return 0

    if only_names:
        known = {name for name, _fn in steps}
        missing = sorted(set(only_names) - known)
        if missing:
            raise ValueError(
                "unknown smoke_check --only check(s): "
                + ", ".join(missing)
                + "\nRun with --list to see available check names."
            )
        selected = set(only_names)
        steps = [(name, fn) for name, fn in steps if name in selected]

    total_steps = len(steps)
    for index, (name, fn) in enumerate(steps, start=1):
        if name == "fast_path_audit":
            print(
                "-- reaping stale smoke children before fast_path_audit --",
                file=sys.stderr,
                flush=True,
            )
            reap_stale_smoke_processes()
        _run_report_step(report, index, total_steps, name, fn)

    if only_names:
        print(json.dumps(report, ensure_ascii=False, indent=2))
        return 0

    platform_check = report["platform_check"]
    auth_status = report["auth_status"]
